import React, { useState } from 'react';
import { GameData, TeamData } from '../types';

interface CustomizationHubProps {
    gameData: GameData;
    setGameData: React.Dispatch<React.SetStateAction<GameData | null>>;
}

const CustomizationHub: React.FC<CustomizationHubProps> = ({ gameData, setGameData }) => {
    const [activeTab, setActiveTab] = useState<'teams' | 'broadcast'>('teams');
    const [selectedTeamId, setSelectedTeamId] = useState(gameData.userTeamId);

    // Team Edit State
    const [teamName, setTeamName] = useState('');
    const [teamLogo, setTeamLogo] = useState('');
    const [teamColor, setTeamColor] = useState('');

    const currentTeam = gameData.allTeamsData.find(t => t.id === selectedTeamId);

    const handleTeamUpdate = () => {
        if (!teamName && !teamLogo && !teamColor) return;
        setGameData(prev => {
            if (!prev) return null;
            const newAllTeamsData = prev.allTeamsData.map(t => {
                if (t.id === selectedTeamId) {
                    return { 
                        ...t, 
                        name: teamName || t.name, 
                        logo: teamLogo || t.logo,
                        primaryColor: teamColor || t.primaryColor
                    };
                }
                return t;
            });
            const newTeams = prev.teams.map(t => {
                if (t.id === selectedTeamId) {
                    return { ...t, name: teamName || t.name };
                }
                return t;
            });
            return { ...prev, allTeamsData: newAllTeamsData, teams: newTeams };
        });
        alert('Team settings updated!');
    };

    return (
        <div className="p-4 h-[calc(100vh-90px)] overflow-y-auto bg-slate-50 dark:bg-[#1A2222]">
            <h2 className="text-2xl font-black text-center mb-6 text-slate-800 dark:text-white uppercase tracking-tighter">Customization Suite</h2>

            <div className="flex justify-center gap-2 mb-6 border-b border-slate-200 dark:border-slate-700 pb-4">
                {['teams', 'broadcast'].map(tab => (
                    <button
                        key={tab}
                        onClick={() => setActiveTab(tab as any)}
                        className={`px-4 py-2 rounded-lg text-sm font-bold uppercase transition-all ${activeTab === tab ? 'bg-teal-500 text-white shadow-lg' : 'bg-slate-200 dark:bg-slate-800 text-slate-500 hover:bg-slate-300 dark:hover:bg-slate-700'}`}
                    >
                        {tab}
                    </button>
                ))}
            </div>

            {activeTab === 'teams' && (
                <div className="space-y-4 animate-fade-in">
                    <div className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700">
                        <label className="block text-[10px] font-black text-slate-500 uppercase mb-2 tracking-widest">Select Team to Customize</label>
                        <select 
                            value={selectedTeamId} 
                            onChange={e => { setSelectedTeamId(e.target.value); setTeamName(''); setTeamLogo(''); setTeamColor(''); }}
                            className="w-full p-3 rounded-lg bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 text-sm font-bold"
                        >
                            {gameData.teams.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                        </select>
                    </div>

                    <div className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 space-y-4">
                        <div>
                            <label className="block text-[10px] font-black text-slate-500 uppercase mb-1 tracking-widest">Team Name</label>
                            <input 
                                type="text" 
                                placeholder={currentTeam?.name} 
                                value={teamName}
                                onChange={e => setTeamName(e.target.value)}
                                className="w-full p-3 rounded-lg bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 text-sm"
                            />
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-slate-500 uppercase mb-1 tracking-widest">Scorecard Hex Color</label>
                            <div className="flex gap-2">
                                <input 
                                    type="color" 
                                    value={teamColor || currentTeam?.primaryColor || '#000000'}
                                    onChange={e => setTeamColor(e.target.value)}
                                    className="h-11 w-11 rounded border border-slate-300 dark:border-slate-600 bg-transparent"
                                />
                                <input 
                                    type="text"
                                    value={teamColor || currentTeam?.primaryColor}
                                    onChange={e => setTeamColor(e.target.value)}
                                    className="flex-grow p-3 rounded-lg bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 text-sm font-mono"
                                />
                            </div>
                        </div>
                        <div>
                            <label className="block text-[10px] font-black text-slate-500 uppercase mb-1 tracking-widest">Logo SVG Source</label>
                            <textarea 
                                placeholder="Paste <svg> code here..." 
                                value={teamLogo}
                                onChange={e => setTeamLogo(e.target.value)}
                                className="w-full p-3 rounded-lg bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 text-[10px] font-mono h-32"
                            />
                        </div>
                        <button onClick={handleTeamUpdate} className="w-full bg-teal-600 hover:bg-teal-500 text-white font-black py-4 rounded-xl uppercase tracking-widest shadow-lg shadow-teal-600/20 transition-all active:scale-95">Save Team Identity</button>
                    </div>

                    <div className="p-4 bg-slate-200 dark:bg-slate-900 rounded-xl text-center border-2 border-dashed border-slate-300 dark:border-slate-800">
                         <div className="w-20 h-20 mx-auto mb-2" dangerouslySetInnerHTML={{ __html: teamLogo || currentTeam?.logo || '' }}></div>
                         <p className="font-black text-xl" style={{ color: teamColor || currentTeam?.primaryColor }}>{teamName || currentTeam?.name}</p>
                         <p className="text-[10px] text-slate-500 uppercase mt-1">Live Preview</p>
                    </div>
                </div>
            )}

            {activeTab === 'broadcast' && (
                <div className="space-y-6 animate-fade-in">
                    <div className="bg-blue-600/10 border border-blue-500/20 p-4 rounded-xl">
                        <p className="text-sm text-blue-600 dark:text-blue-400 font-bold mb-2">Broadcast Info</p>
                        <p className="text-xs text-slate-600 dark:text-slate-400 leading-relaxed">Broadcast settings (TV Channels and Logos) can be managed via the <span className="font-bold text-teal-500">Sponsor Room</span>. Use points to unlock premium networks like PrimeCast Ultra.</p>
                    </div>
                    <div className="p-8 text-center text-slate-400 border-2 border-dashed border-slate-300 dark:border-slate-800 rounded-xl">
                        <p className="text-sm">Additional Graphic Overlays coming in Season 2 updates.</p>
                    </div>
                </div>
            )}
        </div>
    );
};

export default CustomizationHub;

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { Match, GameData, MatchResult, Team, Player, Inning, BattingPerformance, BowlingPerformance } from '../types';
import { getPlayerById, formatOvers } from '../utils';

interface Gameplay2DScreenProps {
    match: Match;
    gameData: GameData;
    onMatchComplete: (result: MatchResult) => void;
    onExit: () => void;
}

// --- Constants ---
const FIELD_WIDTH = 600;
const FIELD_HEIGHT = 650;
const CENTER_X = FIELD_WIDTH / 2;
const CENTER_Y = FIELD_HEIGHT / 2;
const PITCH_START_Y = 220;
const PITCH_END_Y = 460;
const BOUNDARY_RADIUS = 290;
const BALL_RADIUS = 3;
const FIELDER_RADIUS = 8;

type BallState = 'dead' | 'runup' | 'bowling' | 'hit' | 'fielding' | 'boundary' | 'wicket';
type Aggression = 'Defensive' | 'Balanced' | 'Attacking';

interface Fielder {
    id: string;
    x: number;
    y: number;
    role: 'keeper' | 'bowler' | 'fielder';
    speed: number;
    name: string;
}

export const Gameplay2DScreen: React.FC<Gameplay2DScreenProps> = ({ match, gameData, onMatchComplete, onExit }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [allPlayers, setAllPlayers] = useState<Player[]>([]);

    // --- Match State ---
    const [innings, setInnings] = useState<Inning[]>([]);
    const [currentInningIndex, setCurrentInningIndex] = useState(0);
    const [battingTeam, setBattingTeam] = useState<Team | null>(null);
    const [bowlingTeam, setBowlingTeam] = useState<Team | null>(null);
    const [target, setTarget] = useState<number | null>(null);

    // --- Gameplay State ---
    const [strikerId, setStrikerId] = useState<string>('');
    const [nonStrikerId, setNonStrikerId] = useState<string>('');
    const [bowlerId, setBowlerId] = useState<string>('');
    const [aggression, setAggression] = useState<Aggression>('Balanced');
    const [commentary, setCommentary] = useState<string[]>(["Match starting..."]);
    const [modalType, setModalType] = useState<'batter' | 'bowler' | 'openers' | null>(null);
    const [gameOver, setGameOver] = useState(false);

    // --- Selection State ---
    const [selectedModalId, setSelectedModalId] = useState('');
    const [selectedModalId2, setSelectedModalId2] = useState('');

    // --- Physics Ref ---
    const physics = useRef({
        ball: { x: CENTER_X, y: PITCH_START_Y, z: 0, vx: 0, vy: 0, vz: 0, state: 'dead' as BallState, bounces: 0 },
        bowlerPos: { x: CENTER_X, y: PITCH_START_Y - 30 },
        batterPos: { x: CENTER_X, y: PITCH_END_Y },
        fielders: [] as Fielder[],
        draggedFielder: null as number | null,
    });

    const activeTeamData = useMemo(() => {
        if (!battingTeam) return null;
        return gameData.allTeamsData.find(t => t.id === battingTeam.id);
    }, [battingTeam, gameData.allTeamsData]);

    const bowlingTeamData = useMemo(() => {
        if (!bowlingTeam) return null;
        return gameData.allTeamsData.find(t => t.id === bowlingTeam.id);
    }, [bowlingTeam, gameData.allTeamsData]);

    // --- Initialization ---
    useEffect(() => {
        const tA = gameData.teams.find(t => t.name === match.teamA);
        const tB = gameData.teams.find(t => t.name === match.teamB);
        if (!tA || !tB) return;

        const getXI = (t: Team) => {
            const xiIds = gameData.playingXIs[t.id]?.[gameData.currentFormat];
            if (xiIds && xiIds.length === 11) return xiIds.map(id => t.squad.find(p => p.id === id)).filter(Boolean) as Player[];
            return t.squad.slice(0, 11); 
        };

        const pA = getXI(tA);
        const pB = getXI(tB);
        setAllPlayers([...pA, ...pB]);

        const createInning = (team: Team, opp: Team, pList: Player[]): Inning => ({
            teamId: team.id, teamName: team.name,
            score: 0, wickets: 0, overs: '0.0', extras: 0,
            batting: pList.map(p => ({ 
                playerId: p.id, playerName: p.name, runs: 0, balls: 0, fours: 0, sixes: 0, isOut: false, dismissalText: 'not out', dismissal: { type: 'not out', bowlerId: '' } 
            })),
            bowling: getXI(opp).map(p => ({ 
                playerId: p.id, playerName: p.name, overs: '0.0', maidens: 0, runsConceded: 0, wickets: 0, ballsBowled: 0 
            }))
        });

        setInnings([ createInning(tA, tB, pA), createInning(tB, tA, pB) ]);
        setBattingTeam(tA);
        setBowlingTeam(tB);
        setModalType('openers');
    }, []);

    const updateScore = useCallback((runs: number, wkt: number, balls: number = 1, extraType?: string) => {
        setInnings(prev => {
            const newInnings = [...prev];
            const inn = newInnings[currentInningIndex];
            inn.score += runs + (extraType ? 1 : 0);
            inn.wickets += wkt;
            if (extraType) inn.extras++;

            const batter = inn.batting.find(p => p.playerId === strikerId);
            const bowler = inn.bowling.find(p => p.playerId === bowlerId);

            if (batter) {
                batter.runs += runs;
                batter.balls += balls; 
                if (runs === 4) batter.fours++;
                if (runs === 6) batter.sixes++;
                if (wkt) { batter.isOut = true; batter.dismissalText = "Out"; }
            }
            if (bowler) {
                bowler.runsConceded += runs + (extraType ? 1 : 0);
                bowler.ballsBowled += balls;
                bowler.wickets += wkt;
                bowler.overs = formatOvers(bowler.ballsBowled);
            }
            const innBalls = inn.bowling.reduce((acc, b) => acc + b.ballsBowled, 0);
            inn.overs = formatOvers(innBalls);
            return newInnings;
        });

        if (runs % 2 !== 0) {
            setStrikerId(prev => { setNonStrikerId(prev); return nonStrikerId; });
        }
    }, [currentInningIndex, strikerId, bowlerId, nonStrikerId]);

    const processBall = () => {
        const p = physics.current;
        if (p.ball.state === 'dead') return;
        if (p.ball.state === 'runup') {
            p.bowlerPos.y += 3;
            if (p.bowlerPos.y >= PITCH_START_Y) {
                p.ball.state = 'bowling';
                p.ball.x = p.bowlerPos.x;
                p.ball.y = p.bowlerPos.y;
                p.ball.vx = (Math.random() - 0.5) * 2;
                p.ball.vy = 8;
            }
        }
        else if (p.ball.state === 'bowling') {
            p.ball.x += p.ball.vx;
            p.ball.y += p.ball.vy;
            if (p.ball.y >= PITCH_END_Y - 5) determineShotOutcome();
        }
        else if (p.ball.state === 'hit') {
            p.ball.x += p.ball.vx;
            p.ball.y += p.ball.vy;
            if (p.ball.z <= 0) { p.ball.vx *= 0.98; p.ball.vy *= 0.98; }
            else { p.ball.vx *= 0.99; p.ball.vy *= 0.99; }
            if (p.ball.z > 0 || p.ball.vz > 0) {
                p.ball.z += p.ball.vz;
                p.ball.vz -= 0.3;
                if (p.ball.z < 0) { p.ball.z = 0; p.ball.vz = -p.ball.vz * 0.5; p.ball.bounces++; }
            }
            const distFromCenter = Math.sqrt(Math.pow(p.ball.x - CENTER_X, 2) + Math.pow(p.ball.y - CENTER_Y, 2));
            if (distFromCenter >= BOUNDARY_RADIUS) {
                p.ball.state = 'boundary';
                const isSix = p.ball.bounces === 0;
                setCommentary(prev => [isSix ? "SIX! Over the fence!" : "FOUR! Beautiful shot!", ...prev]);
                updateScore(isSix ? 6 : 4, 0);
                resetBall();
                return;
            }
            let intercepted = false;
            const sortedFielders = p.fielders.map(f => ({ ...f, dist: Math.sqrt(Math.pow(f.x - p.ball.x, 2) + Math.pow(f.y - p.ball.y, 2)) })).sort((a, b) => a.dist - b.dist);
            sortedFielders.slice(0, 2).forEach(f => {
                const originalFielder = p.fielders.find(of => of.id === f.id);
                if (!originalFielder) return;
                const dx = p.ball.x - originalFielder.x;
                const dy = p.ball.y - originalFielder.y;
                const angle = Math.atan2(dy, dx);
                originalFielder.x += Math.cos(angle) * (originalFielder.speed * 3);
                originalFielder.y += Math.sin(angle) * (originalFielder.speed * 3);
                if (f.dist < FIELDER_RADIUS + BALL_RADIUS + 5) {
                    if (p.ball.z > 5 && p.ball.bounces === 0) {
                        p.ball.state = 'wicket'; intercepted = true;
                        setCommentary(prev => ["OUT! Fantastic catch!", ...prev]);
                        if (battingTeam?.id === gameData.userTeamId) setTimeout(() => setModalType('batter'), 1500);
                        else setTimeout(() => autoSelectBatter(), 1500);
                        updateScore(0, 1); resetBall();
                    } else if (p.ball.z < 10) {
                        p.ball.vx = 0; p.ball.vy = 0; p.ball.state = 'fielding'; intercepted = true;
                        const distFromPitch = Math.abs(p.ball.y - PITCH_END_Y);
                        const runs = distFromPitch > 200 ? 3 : distFromPitch > 100 ? 2 : distFromPitch > 30 ? 1 : 0;
                        setCommentary(prev => [runs > 0 ? `${runs} runs taken.` : "Defended well.", ...prev]);
                        updateScore(runs, 0); resetBall();
                    }
                }
            });
            if (!intercepted && Math.abs(p.ball.vx) < 0.1 && Math.abs(p.ball.vy) < 0.1) {
                p.ball.state = 'fielding';
                const distFromPitch = Math.abs(p.ball.y - PITCH_END_Y);
                const runs = distFromPitch > 120 ? 2 : distFromPitch > 40 ? 1 : 0;
                setCommentary(prev => [runs > 0 ? `${runs} runs.` : "Dot ball.", ...prev]);
                updateScore(runs, 0); resetBall();
            }
        }
    };

    const determineShotOutcome = () => {
        const p = physics.current;
        const batter = getPlayerById(strikerId, allPlayers);
        const bowler = getPlayerById(bowlerId, allPlayers);
        let batSkill = batter.battingSkill;
        let bowlSkill = bowler.secondarySkill;
        if (aggression === 'Attacking') batSkill *= 1.2;
        if (aggression === 'Defensive') batSkill *= 0.8;
        const diff = batSkill - bowlSkill + (Math.random() * 40 - 20);
        p.ball.state = 'hit';
        p.ball.bounces = 0;
        if (diff < -30 && Math.random() < 0.3) {
            p.ball.state = 'wicket';
            setCommentary(prev => ["OUT! Bowled him!", ...prev]);
            updateScore(0, 1);
            if (battingTeam?.id === gameData.userTeamId) setTimeout(() => setModalType('batter'), 1500);
            else setTimeout(() => autoSelectBatter(), 1500);
            resetBall();
            return;
        }
        let power = 2 + Math.random() * 5;
        let lift = 0;
        if (aggression === 'Attacking') { power += 5; lift += Math.random() * 10; }
        if (diff > 20) power += 3;
        const angle = Math.random() * Math.PI * 2;
        p.ball.vx = Math.cos(angle) * power;
        p.ball.vy = Math.sin(angle) * power;
        p.ball.vz = lift;
    };

    const resetBall = () => {
        setTimeout(() => {
            if (!gameOver) {
                physics.current.ball = { x: CENTER_X, y: PITCH_START_Y, z: 0, vx: 0, vy: 0, vz: 0, state: 'dead', bounces: 0 };
                physics.current.bowlerPos = { x: CENTER_X, y: PITCH_START_Y - 30 };
                setTimeout(() => { if (physics.current.ball.state === 'dead') physics.current.ball.state = 'runup'; }, 500);
            }
        }, 2000);
    };

    useEffect(() => {
        let frameId: number;
        const ctx = canvasRef.current?.getContext('2d');
        const loop = () => { processBall(); if (ctx) draw(ctx); frameId = requestAnimationFrame(loop); };
        loop();
        return () => cancelAnimationFrame(frameId);
    }, []);

    const draw = (ctx: CanvasRenderingContext2D) => {
        ctx.fillStyle = "#387333";
        ctx.fillRect(0, 0, FIELD_WIDTH, FIELD_HEIGHT);
        ctx.strokeStyle = "rgba(255,255,255,0.3)";
        ctx.beginPath(); ctx.arc(CENTER_X, CENTER_Y, 150, 0, Math.PI*2); ctx.stroke();
        ctx.strokeStyle = "white"; ctx.lineWidth = 3;
        ctx.beginPath(); ctx.arc(CENTER_X, CENTER_Y, BOUNDARY_RADIUS, 0, Math.PI*2); ctx.stroke();
        ctx.fillStyle = "#d9cba0";
        ctx.fillRect(CENTER_X - 15, PITCH_START_Y, 30, PITCH_END_Y - PITCH_START_Y);
        ctx.strokeStyle = "white"; ctx.lineWidth = 1;
        ctx.beginPath(); ctx.moveTo(CENTER_X - 20, PITCH_START_Y); ctx.lineTo(CENTER_X + 20, PITCH_START_Y); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(CENTER_X - 20, PITCH_END_Y); ctx.lineTo(CENTER_X + 20, PITCH_END_Y); ctx.stroke();
        physics.current.fielders.forEach((f, i) => {
            ctx.fillStyle = i === physics.current.draggedFielder ? "white" : (bowlingTeamData?.primaryColor || "yellow");
            ctx.beginPath(); ctx.arc(f.x, f.y, FIELDER_RADIUS, 0, Math.PI*2); ctx.fill();
            ctx.fillStyle = "black"; ctx.font = "8px Arial"; ctx.fillText(f.name, f.x - 5, f.y - 8);
        });
        const b = physics.current.ball;
        if (b.state !== 'dead') {
            ctx.fillStyle = "rgba(0,0,0,0.4)";
            ctx.beginPath(); ctx.arc(b.x, b.y, BALL_RADIUS + (b.z/3), 0, Math.PI*2); ctx.fill();
            ctx.fillStyle = "white"; ctx.beginPath(); ctx.arc(b.x, b.y - b.z, BALL_RADIUS, 0, Math.PI*2); ctx.fill();
        }
        ctx.fillStyle = bowlingTeamData?.primaryColor || "red";
        ctx.beginPath(); ctx.arc(physics.current.bowlerPos.x, physics.current.bowlerPos.y, FIELDER_RADIUS, 0, Math.PI*2); ctx.fill();
        ctx.fillStyle = activeTeamData?.primaryColor || "blue";
        ctx.beginPath(); ctx.arc(CENTER_X, PITCH_END_Y + 5, FIELDER_RADIUS, 0, Math.PI*2); ctx.fill();
    };

    const confirmOpeners = () => {
        if (selectedModalId && selectedModalId2) {
            setStrikerId(selectedModalId);
            setNonStrikerId(selectedModalId2);
            setModalType(null);
            initFielders();
            resetBall();
        }
    };

    const initFielders = () => {
        const fielders: Fielder[] = [];
        fielders.push({ id: 'wk', x: CENTER_X, y: PITCH_END_Y + 40, role: 'keeper', speed: 0.8, name: 'WK' });
        fielders.push({ id: 'bwl', x: CENTER_X, y: PITCH_START_Y - 20, role: 'bowler', speed: 1.0, name: 'BWL' });
        for(let i=0; i<7; i++) {
            const angle = (i * (360/7)) * (Math.PI/180);
            fielders.push({ id: `f${i}`, x: CENTER_X + Math.cos(angle) * 180, y: CENTER_Y + Math.sin(angle) * 180, role: 'fielder', speed: 0.9 + Math.random()*0.2, name: `F${i+1}` });
        }
        physics.current.fielders = fielders;
    };

    const autoSelectBatter = () => {
        const inn = innings[currentInningIndex];
        const next = inn.batting.find(b => !b.isOut && b.playerId !== strikerId && b.playerId !== nonStrikerId);
        if (next) setStrikerId(next.playerId);
    };

    const curInn = innings[currentInningIndex];

    return (
        <div className="flex flex-col h-full bg-black text-white font-sans overflow-hidden">
            {/* Scoreboard Overlay - Broadcast Style */}
            <div className="absolute top-10 left-0 right-0 z-50 px-4 pointer-events-none">
                <div className="max-w-xl mx-auto flex items-stretch h-14 bg-black/60 backdrop-blur-md rounded shadow-2xl overflow-hidden border border-white/10">
                    <div className="w-12 flex items-center justify-center bg-white">
                         <div className="w-8 h-8" dangerouslySetInnerHTML={{ __html: activeTeamData?.logo || '' }}></div>
                    </div>
                    <div className="flex-grow flex items-center px-4" style={{ backgroundColor: activeTeamData?.primaryColor }}>
                        <div className="flex flex-col">
                            <span className="text-[10px] font-black text-white/70 uppercase tracking-widest">{activeTeamData?.name}</span>
                            <span className="text-3xl font-black text-white leading-none">{curInn?.score}-{curInn?.wickets}</span>
                        </div>
                        <div className="ml-auto text-right">
                             <div className="text-[10px] font-black text-white/70 uppercase">Overs</div>
                             <div className="text-xl font-black text-white leading-none">{curInn?.overs}</div>
                        </div>
                    </div>
                    <div className="w-40 bg-slate-900 flex flex-col justify-center px-3 border-l border-white/10">
                         <div className="flex justify-between items-center text-[10px] font-bold text-slate-400">
                             <span className="uppercase">{getPlayerById(strikerId, allPlayers).name}</span>
                             <span className="text-white">{curInn?.batting.find(b => b.playerId === strikerId)?.runs}</span>
                         </div>
                         <div className="flex justify-between items-center text-[10px] font-bold text-slate-500">
                             <span className="uppercase">{getPlayerById(nonStrikerId, allPlayers).name}</span>
                             <span className="text-white/60">{curInn?.batting.find(b => b.playerId === nonStrikerId)?.runs}</span>
                         </div>
                    </div>
                    {target && (
                        <div className="w-24 bg-white/10 flex flex-col items-center justify-center border-l border-white/10">
                            <span className="text-[9px] font-black uppercase text-slate-400">Target</span>
                            <span className="text-lg font-black text-white">{target + 1}</span>
                        </div>
                    )}
                </div>
            </div>

            <div className="flex-1 relative bg-[#2e5a27] flex justify-center">
                <canvas ref={canvasRef} width={FIELD_WIDTH} height={FIELD_HEIGHT} className="h-full w-auto object-contain cursor-pointer touch-none" onMouseDown={(e) => {
                    if (bowlingTeam?.id !== gameData.userTeamId) return;
                    const rect = canvasRef.current?.getBoundingClientRect();
                    if (!rect) return;
                    const x = (e.clientX - rect.left) * (FIELD_WIDTH / rect.width);
                    const y = (e.clientY - rect.top) * (FIELD_HEIGHT / rect.height);
                    const idx = physics.current.fielders.findIndex(f => Math.sqrt(Math.pow(f.x - x, 2) + Math.pow(f.y - y, 2)) < FIELDER_RADIUS * 2);
                    if (idx !== -1) physics.current.draggedFielder = idx;
                }} onMouseMove={(e) => {
                    if (physics.current.draggedFielder === null) return;
                    const rect = canvasRef.current?.getBoundingClientRect();
                    if (!rect) return;
                    physics.current.fielders[physics.current.draggedFielder].x = (e.clientX - rect.left) * (FIELD_WIDTH / rect.width);
                    physics.current.fielders[physics.current.draggedFielder].y = (e.clientY - rect.top) * (FIELD_HEIGHT / rect.height);
                }} onMouseUp={() => physics.current.draggedFielder = null} />

                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 bg-black/80 px-6 py-2 rounded-full border border-white/20">
                    <p className="text-sm font-bold tracking-tight text-center">{commentary[0]}</p>
                </div>
            </div>

            <div className="p-4 bg-slate-900 border-t border-white/5">
                <div className="flex gap-4 mb-4">
                    {(['Defensive', 'Balanced', 'Attacking'] as Aggression[]).map(agg => (
                        <button key={agg} onClick={() => setAggression(agg)} className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-lg transition-all ${aggression === agg ? 'bg-teal-500 text-white shadow-lg shadow-teal-500/20' : 'bg-slate-800 text-slate-500'}`}>{agg}</button>
                    ))}
                </div>
                <div className="flex gap-3">
                    {physics.current.ball.state === 'dead' && !gameOver && !modalType && (
                        <button onClick={resetBall} className="flex-grow bg-white text-slate-900 font-black py-4 rounded-xl uppercase tracking-widest shadow-xl active:scale-95 transition-all">Bowl Next</button>
                    )}
                    <button onClick={onExit} className="px-6 bg-red-600/20 text-red-500 font-black py-4 rounded-xl uppercase tracking-widest border border-red-500/30">Exit</button>
                </div>
            </div>

            {modalType === 'openers' && (
                <div className="absolute inset-0 bg-slate-950/95 z-[100] flex flex-col items-center justify-center p-6">
                    <h3 className="text-3xl font-black mb-8 uppercase italic tracking-tighter">Select Opening Pair</h3>
                    <div className="w-full max-w-sm space-y-4">
                        <select className="w-full p-4 bg-slate-900 rounded-xl border border-slate-700 text-white font-bold" value={selectedModalId} onChange={e => setSelectedModalId(e.target.value)}>
                            <option value="">Striker</option>
                            {innings[currentInningIndex].batting.filter(p => !p.isOut).map(p => <option key={p.playerId} value={p.playerId}>{p.playerName}</option>)}
                        </select>
                        <select className="w-full p-4 bg-slate-900 rounded-xl border border-slate-700 text-white font-bold" value={selectedModalId2} onChange={e => setSelectedModalId2(e.target.value)}>
                            <option value="">Non-Striker</option>
                            {innings[currentInningIndex].batting.filter(p => !p.isOut && p.playerId !== selectedModalId).map(p => <option key={p.playerId} value={p.playerId}>{p.playerName}</option>)}
                        </select>
                        <button disabled={!selectedModalId || !selectedModalId2} onClick={confirmOpeners} className="w-full bg-teal-500 py-5 rounded-2xl font-black uppercase tracking-widest disabled:opacity-30">Start Innings</button>
                    </div>
                </div>
            )}

            {modalType === 'batter' && (
                <div className="absolute inset-0 bg-slate-950/95 z-[100] flex flex-col items-center justify-center p-6">
                    <h3 className="text-3xl font-black mb-8 uppercase italic tracking-tighter">New Batter In</h3>
                    <div className="w-full max-w-sm space-y-4">
                        <select className="w-full p-4 bg-slate-900 rounded-xl border border-slate-700 text-white font-bold" value={selectedModalId} onChange={e => setSelectedModalId(e.target.value)}>
                            <option value="">Select Player</option>
                            {innings[currentInningIndex].batting.filter(p => !p.isOut && p.playerId !== strikerId && p.playerId !== nonStrikerId).map(p => <option key={p.playerId} value={p.playerId}>{p.playerName}</option>)}
                        </select>
                        <button disabled={!selectedModalId} onClick={() => { setStrikerId(selectedModalId); setModalType(null); resetBall(); }} className="w-full bg-teal-500 py-5 rounded-2xl font-black uppercase tracking-widest disabled:opacity-30">Confirm</button>
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { GameData, CareerScreen, MatchResult, Player, Format, PromotionRecord, Team, LiveMatchState } from '../types';
import { TEAMS, INITIAL_SPONSORSHIPS, INITIAL_NEWS } from '../data';
import { Icons } from './Icons';
import { getPlayerById, generateLeagueSchedule, negotiateSponsorships, generateMatchNews, generatePreMatchNews } from '../utils';
import { useSimulation } from '../hooks/useSimulation';

// Import screens
import Dashboard from './Dashboard';
import Schedule from './Schedule';
import News from './News';
import Lineups from './Lineups';
import Editor from './Editor';
import Standings from './Standings';
import Stats from './Stats';
import Settings from './Settings';
import PlayerProfile from './PlayerProfile';
import MatchResultScreen from './MatchResultScreen';
import ForwardResultsScreen from './ForwardResultsScreen';
import AwardsAndRecordsScreen from './AwardsRecordsScreen';
import EndOfFormatScreen from './EndOfFormatScreen';
import Transfers from './Transfers';
import ComparisonScreen from './ComparisonScreen';
import LiveMatchScreen from './LiveMatchScreen';
import SponsorRoom from './SponsorRoom';
import CustomizationHub from './CustomizationHub';
import { Gameplay2DScreen } from './Gameplay2DScreen';

interface CareerHubProps {
    gameData: GameData;
    setGameData: React.Dispatch<React.SetStateAction<GameData | null>>;
    onResetGame: () => void;
    theme: 'light' | 'dark';
    setTheme: (theme: 'light' | 'dark') => void;
    saveGame: () => void;
    loadGame: () => void;
    showFeedback: (message: string, type?: 'success' | 'error') => void;
}

const BottomNavBar = ({ activeScreen, setScreen }: { activeScreen: CareerScreen, setScreen: (screen: CareerScreen) => void }) => {
    const navItems = [
        { name: 'HOME', screen: 'DASHBOARD' as CareerScreen, icon: Icons.Home },
        { name: 'TABLE', screen: 'LEAGUES' as CareerScreen, icon: Icons.Podium },
        { name: 'CUSTOM', screen: 'CUSTOMIZATION' as CareerScreen, icon: Icons.Editor }, // Repurposed for Custom Hub
        { name: 'STATS', screen: 'STATS' as CareerScreen, icon: Icons.ChartPie },
        { name: 'SETTINGS', screen: 'SETTINGS' as CareerScreen, icon: Icons.Settings },
    ];
    return (
        <nav className="bg-gray-100/80 dark:bg-[#101F1F] border-t border-gray-300/50 dark:border-gray-700/50 flex justify-around items-center h-[90px] pb-4 backdrop-blur-sm">
            {navItems.map(item => (
                <button
                    key={item.name}
                    onClick={() => setScreen(item.screen)}
                    className={`flex flex-col items-center justify-center space-y-1 w-1/5 pt-2 transition-colors duration-200 ${activeScreen === item.screen ? 'text-teal-500' : 'text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white'}`}
                >
                    <item.icon />
                    <span className="text-[10px] font-bold tracking-wider">{item.name}</span>
                </button>
            ))}
        </nav>
    );
};

const CareerHub: React.FC<CareerHubProps> = ({ gameData, setGameData, onResetGame, theme, setTheme, saveGame, loadGame, showFeedback }) => {
    const [screen, setScreen] = useState<CareerScreen>('DASHBOARD');
    const [selectedPlayer, setSelectedPlayer] = useState<Player | null>(null);
    const [playerProfileFormat, setPlayerProfileFormat] = useState<Format>(gameData.currentFormat);
    const [selectedMatchResult, setSelectedMatchResult] = useState<MatchResult | null>(null);
    const [forwardSimResults, setForwardSimResults] = useState<MatchResult[]>([]);

    const { runSimulationForCurrentFormat, updateStatsFromMatch } = useSimulation(gameData, setGameData);

    useEffect(() => {
        if (gameData && (!gameData.sponsorships || !gameData.popularity || !gameData.news)) {
             setGameData(prev => {
                 if (!prev) return null;
                 return {
                     ...prev,
                     popularity: prev.popularity ?? 50,
                     sponsorships: prev.sponsorships ?? INITIAL_SPONSORSHIPS,
                     news: prev.news ?? INITIAL_NEWS
                 };
             });
        }
    }, [gameData, setGameData]);

    const userTeam = useMemo(() => gameData.teams.find(t => t.id === gameData.userTeamId) || gameData.teams[0], [gameData]);

    useEffect(() => {
        const schedule = gameData.schedule[gameData.currentFormat];
        const currentMatchIndex = gameData.currentMatchIndex[gameData.currentFormat];
        if (currentMatchIndex >= schedule.length) {
            const awardExists = gameData.awardsHistory.some(a => a.season === gameData.currentSeason && a.format === gameData.currentFormat);
            if (!awardExists) {
                // Award calculation logic (simplified for brevity, matching previous functionality)
                setScreen('END_OF_FORMAT');
            }
        }
    }, [gameData.currentMatchIndex, gameData.currentFormat, gameData.currentSeason]);

    const handleUpdateCaptain = (teamId: string, format: Format, playerId: string) => {
        setGameData(prevData => {
            if (!prevData) return null;
            return {
                ...prevData,
                teams: prevData.teams.map(t => {
                    if (t.id === teamId) return { ...t, captains: { ...t.captains, [format]: playerId } };
                    return t;
                })
            };
        });
        showFeedback("Captain updated!");
    };

    const handleUpdatePlayingXI = (teamId: string, format: Format, newXI: string[]) => {
        setGameData(prevData => {
            if (!prevData) return null;
            return {
                ...prevData,
                playingXIs: { ...prevData.playingXIs, [teamId]: { ...(prevData.playingXIs[teamId] || {}), [format]: newXI } }
            };
        });
    };

    const handlePlayMatch = () => {
        const schedule = gameData.schedule[gameData.currentFormat];
        const currentMatchIndex = gameData.currentMatchIndex[gameData.currentFormat];
        if (currentMatchIndex >= schedule.length) return;
        setScreen('LIVE_MATCH');
    };

    const handleLiveMatchComplete = (result: MatchResult) => {
        const updatedData = updateStatsFromMatch(result, gameData.currentFormat, gameData);
        updatedData.currentMatchIndex[gameData.currentFormat]++;
        updatedData.activeMatch = null; 
        const sponsorship = updatedData.sponsorships?.[updatedData.currentFormat] || INITIAL_SPONSORSHIPS[updatedData.currentFormat];
        updatedData.news = [generateMatchNews(result, updatedData.currentFormat, sponsorship), ...updatedData.news].slice(0, 50);
        setGameData(updatedData);
        setSelectedMatchResult(result);
        setScreen('MATCH_RESULT');
    };

    const renderScreen = () => {
        const commonProps = { gameData, userTeam, setGameData, setScreen, showFeedback };
        switch(screen) {
            case 'DASHBOARD': return <Dashboard {...commonProps} handlePlayMatch={handlePlayMatch} handleForwardDay={() => {}} />;
            case 'LEAGUES': return <Standings gameData={gameData} />; 
            case 'LINEUPS': return <Lineups {...commonProps} handleUpdatePlayingXI={handleUpdatePlayingXI} handleUpdateCaptain={handleUpdateCaptain} />;
            case 'CUSTOMIZATION': return <CustomizationHub {...commonProps} />;
            case 'NEWS': return <News news={gameData.news} />;
            case 'STATS': return <Stats gameData={gameData} viewPlayerProfile={(p, f) => { setSelectedPlayer(p); setPlayerProfileFormat(f); setScreen('PLAYER_PROFILE'); }} />;
            case 'SETTINGS': return <Settings onResetGame={onResetGame} theme={theme} setTheme={setTheme} saveGame={saveGame} loadGame={loadGame} />;
            case 'MATCH_RESULT': return <MatchResultScreen result={selectedMatchResult} onBack={() => setScreen('DASHBOARD')} userTeamId={gameData.userTeamId} />;
            case 'SPONSOR_ROOM': return <SponsorRoom gameData={gameData} setGameData={setGameData} />;
            case 'LIVE_MATCH': return <Gameplay2DScreen match={gameData.schedule[gameData.currentFormat][gameData.currentMatchIndex[gameData.currentFormat]]} gameData={gameData} onMatchComplete={handleLiveMatchComplete} onExit={() => setScreen('DASHBOARD')} />;
            default: return <Dashboard {...commonProps} handlePlayMatch={handlePlayMatch} handleForwardDay={() => {}} />;
        }
    }

    return (
        <div className="flex flex-col h-full">
            <main className="flex-grow overflow-y-auto">{renderScreen()}</main>
            <BottomNavBar activeScreen={screen} setScreen={setScreen} />
        </div>
    );
};

export default CareerHub;

export enum Format {
    T20 = 'Premier T20 League',
    ODI = 'Premier One-Day Cup',
    FIRST_CLASS = 'Premier First-Class Shield',
    DEVELOPMENT_T20 = 'Development T20 Cup',
    DEVELOPMENT_ODI = 'Development List-A Cup',
