                </div>
                <div className="w-full h-full flex items-center justify-center p-2">
                    <svg viewBox="0 0 400 400" className="h-full w-full max-h-[60vh] max-w-md drop-shadow-2xl" preserveAspectRatio="xMidYMid meet">
                        <circle cx="200" cy="200" r="190" fill="#35682d" stroke="#ffffff" strokeWidth="2" strokeOpacity="0.8" />
                        <rect x="196" y="170" width="8" height="60" fill="#d2b48c" stroke="#bfa07a" strokeWidth="0.5" />
                        {lastBall && <circle cx="200" cy="175" r="1.5" fill="white" className="animate-ball" />}
                    </svg>
                </div>
                <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 pointer-events-none z-20">
                    {lastBall && (
                        <div className={`flex items-center justify-center rounded-full h-20 w-20 ${isWicket ? 'bg-red-600' : isBoundary ? 'bg-purple-600' : 'bg-slate-800/80'} border-4 border-white shadow-2xl animate-bounce`}><span className="text-3xl font-black text-white">{lastBall === 'W' ? 'OUT' : lastBall}</span></div>
                    )}
                </div>
                <div className="absolute bottom-2 right-2 z-10"><button onClick={() => setShowMatchCentre(true)} className="bg-slate-800/90 text-xs font-bold text-white px-4 py-2 rounded-full border border-slate-600 shadow-lg flex items-center gap-2 animate-pulse"><Icons.ChartPie /> Match Centre</button></div>
            </div>
            <div className="bg-slate-800 border-t border-slate-700 p-1 flex-shrink-0">
                <div className="flex items-stretch bg-slate-900/50 rounded overflow-hidden text-xs">
                    <div className="flex-1 p-2 border-r border-slate-700"><div className="text-[9px] text-slate-500 uppercase font-bold">Bowling</div><div className="font-bold text-white truncate">{bowler?.playerName}</div></div>
                    <div className="flex-[2] flex"><div className={`flex-1 p-2 border-r border-slate-700/50 ${striker?.playerId === currentBatters.strikerId ? 'bg-yellow-900/20' : ''}`}><div className="text-[9px] text-yellow-500/70 uppercase font-bold">Striker</div><div className="font-bold text-yellow-400 truncate">{striker?.playerName}</div></div></div>
                </div>
            </div>
            <div className="bg-slate-900 p-3 pb-6 flex-shrink-0">
                 <div className="flex gap-2 mb-3">
                    {isUserBatting && <StrategyToggle label="Batting Tactics" value={strategies.batting} onChange={setBattingStrategy} />}
                    {isUserBowling && <StrategyToggle label="Bowling Tactics" value={strategies.bowling} onChange={setBowlingStrategy} />}
                 </div>
                <div className="flex gap-2">
                    {state.status === 'completed' ? <button onClick={() => onExit()} className="flex-1 bg-red-600 hover:bg-red-700 text-white font-bold py-3 rounded-lg shadow-lg transition-transform active:scale-95 uppercase tracking-wider">End Match</button> : (
                        <>
                            <button onClick={playBall} className={`flex-1 ${isUserBatting ? 'bg-blue-600 hover:bg-blue-500' : 'bg-emerald-600 hover:bg-emerald-500'} text-white font-bold py-3 rounded-lg shadow-lg transition-transform active:scale-95 flex items-center justify-center gap-2`}><Icons.Play className="h-5 w-5" /><span className="hidden sm:inline">{isUserBatting ? 'PLAY' : 'BOWL'}</span></button>
                            <button onClick={playOver} className="flex-1 bg-slate-600 hover:bg-slate-500 text-white font-bold py-3 rounded-lg shadow-lg transition-transform active:scale-95 flex items-center justify-center gap-2"><span className="text-lg">⏭</span><span className="hidden sm:inline">OVER</span></button>
                        </>
                    )}
                </div>
            </div>
        </div>
    );
};

