import React from 'react';
import { GameData, Team, CareerScreen } from '../types';
import { Icons, ActionButton, SlantedContainer } from './CommonUI';
import { resolveMatchPlaceholders } from '../utils';

interface DashboardProps {
    gameData: GameData;
    userTeam: Team | null;
    setScreen: (screen: CareerScreen) => void;
    handlePlayMatch: () => void;
    handleForwardDay: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ gameData, userTeam, setScreen, handlePlayMatch, handleForwardDay }) => {
    const currentSchedule = gameData.schedule[gameData.currentFormat];
    const matchIndex = gameData.currentMatchIndex[gameData.currentFormat];
    const sponsorship = gameData.sponsorships?.[gameData.currentFormat];

    if (matchIndex >= currentSchedule.length) {
        return <div className="p-4 text-center h-full flex items-center justify-center font-bold text-slate-500 italic">Season Complete. Processing results...</div>;
    }

    const nextMatch = resolveMatchPlaceholders(currentSchedule[matchIndex], gameData, gameData.currentFormat);
    const isUserMatch = userTeam ? (nextMatch.teamA === userTeam.name || nextMatch.teamB === userTeam.name) : false;

    return (
        <div className="p-4 space-y-4">
            <header className="text-center pb-2 border-b border-white/5">
                <p className="text-[10px] font-black text-pink-500 tracking-[0.2em] mb-1">SEASON {gameData.currentSeason}</p>
                <div className="flex items-center justify-center gap-3">
                    <div className={`w-8 h-8 ${sponsorship?.logoColor || 'text-white'}`} dangerouslySetInnerHTML={{__html: sponsorship?.tournamentLogo || ''}}></div>
                    <h1 className="text-3xl font-black italic tracking-tighter uppercase leading-none">
                        {sponsorship?.sponsorName} <span className="font-light text-slate-400">{sponsorship?.tournamentName}</span>
                    </h1>
                </div>
            </header>

            <SlantedContainer className="bg-zinc-900 border border-white/5 p-6 rounded-2xl">
                <h3 className="text-[10px] font-black text-pink-500 uppercase tracking-widest text-center mb-4">Upcoming Fixture</h3>
                <div className="flex items-center justify-between gap-4">
                    <div className="text-center flex-1">
                        <div className="w-12 h-12 mx-auto mb-2" dangerouslySetInnerHTML={{__html: gameData.allTeamsData.find(t => t.name === nextMatch.teamA)?.logo || ''}}></div>
                        <p className="font-black italic text-sm truncate">{nextMatch.teamA}</p>
                    </div>
                    <div className="text-center px-4">
                        <span className="text-xs font-black text-slate-600">VS</span>
                    </div>
                    <div className="text-center flex-1">
                        <div className="w-12 h-12 mx-auto mb-2" dangerouslySetInnerHTML={{__html: gameData.allTeamsData.find(t => t.name === nextMatch.teamB)?.logo || ''}}></div>
                        <p className="font-black italic text-sm truncate">{nextMatch.teamB}</p>
                    </div>
                </div>

                {isUserMatch ? (
                    <ActionButton onClick={handlePlayMatch} className="w-full mt-6 flex items-center justify-center gap-3">
                        <Icons.PlayMatch /> PLAY MATCH
                    </ActionButton>
                ) : (
                    <ActionButton onClick={handleForwardDay} variant="secondary" className="w-full mt-6">
                        SIMULATE DAY
                    </ActionButton>
                )}
            </SlantedContainer>

            <div className="grid grid-cols-3 gap-3">
                {[
                    { s: 'LEAGUES', i: Icons.Leagues, l: 'League' },
                    { s: 'LINEUPS', i: Icons.Lineups, l: 'Squad' },
                    { s: 'TRANSFERS', i: Icons.Transfers, l: 'Market' },
                    { s: 'STATS', i: Icons.ChartPie, l: 'Records' },
                    { s: 'EDITOR', i: Icons.Editor, l: 'Edit' },
                    { s: 'NEWS', i: Icons.News, l: 'News' }
                ].map(item => (
                    <button key={item.s} onClick={() => setScreen(item.s as any)} className="bg-zinc-900/50 border border-white/5 p-4 rounded-2xl flex flex-col items-center gap-2 hover:bg-zinc-800 transition-all group">
                        <item.i />
                        <span className="text-[10px] font-black uppercase tracking-tighter text-slate-400 group-hover:text-white">{item.l}</span>
                    </button>
                ))}
            </div>
        </div>
    );
};

