import React, { useState } from 'react';
import { GameData, Brand, TVChannel } from '../types';
import { Icons } from './Icons';

interface CustomizationHubProps {
    gameData: GameData;
    setGameData: React.Dispatch<React.SetStateAction<GameData | null>>;
}

const CustomizationHub: React.FC<CustomizationHubProps> = ({ gameData, setGameData }) => {
    const [activeTab, setActiveTab] = useState<'teams' | 'brands' | 'tv'>('teams');
    const [selectedTeamId, setSelectedTeamId] = useState(gameData.teams[0].id);

    const teamData = gameData.allTeamsData.find(t => t.id === selectedTeamId)!;

    // Team Edit State
    const [teamName, setTeamName] = useState(teamData.name);
    const [teamShortName, setTeamShortName] = useState(teamData.shortName);
    const [teamLogo, setTeamLogo] = useState(teamData.logo);
    const [primaryColor, setPrimaryColor] = useState(teamData.primaryColor);

    // Brand Edit State
    const [brandName, setBrandName] = useState('');
    const [brandColor, setBrandColor] = useState('text-white');
    const [brandLogo, setBrandLogo] = useState('<svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="10" fill="currentColor"/></svg>');

    const handleTeamUpdate = () => {
        setGameData(prev => {
            if (!prev) return null;
            const newAllTeamsData = prev.allTeamsData.map(t => {
                if (t.id === selectedTeamId) {
                    return { ...t, name: teamName, shortName: teamShortName, logo: teamLogo, primaryColor };
                }
                return t;
            });
            const newTeams = prev.teams.map(t => {
                if (t.id === selectedTeamId) {
                    return { ...t, name: teamName, shortName: teamShortName, primaryColor };
                }
                return t;
            });
            return { ...prev, allTeamsData: newAllTeamsData, teams: newTeams };
        });
    };

    const handleAddBrand = () => {
        if (!brandName) return;
        const newBrand: Brand = {
            name: brandName,
            color: brandColor,
            style: 'font-bold',
            logo: brandLogo
        };
        setGameData(prev => {
            if (!prev) return null;
            return { ...prev, availableBrands: [...(prev.availableBrands || []), newBrand] };
        });
        setBrandName('');
    };

    return (
        <div className="p-4 h-[calc(100vh-90px)] overflow-y-auto bg-slate-50 dark:bg-[#101817] flex flex-col font-sans">
            <h2 className="text-3xl font-black italic text-center mb-6 text-slate-800 dark:text-white uppercase tracking-tighter">Identity Studio</h2>

            <div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-xl gap-1 mb-6">
                {['teams', 'brands', 'tv'].map(tab => (
                    <button
                        key={tab}
                        onClick={() => setActiveTab(tab as any)}
                        className={`flex-1 py-2 rounded-lg text-xs font-black uppercase transition-all ${activeTab === tab ? 'bg-teal-500 text-white shadow' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                        {tab}
                    </button>
                ))}
            </div>

            {activeTab === 'teams' && (
                <div className="space-y-6 animate-fade-in pb-10">
                    <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800">
                        <div className="mb-4">
                            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Select Franchise</label>
                            <select 
                                value={selectedTeamId} 
                                onChange={e => {
                                    const tid = e.target.value;
                                    const t = gameData.allTeamsData.find(x => x.id === tid)!;
                                    setSelectedTeamId(tid);
                                    setTeamName(t.name);
                                    setTeamShortName(t.shortName);
                                    setTeamLogo(t.logo);
                                    setPrimaryColor(t.primaryColor);
                                }}
                                className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-800 border-none font-bold text-lg"
                            >
                                {gameData.teams.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                            </select>
                        </div>

                        <div className="grid grid-cols-2 gap-4 mb-4">
                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Name</label>
                                <input type="text" value={teamName} onChange={e => setTeamName(e.target.value)} className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-800 font-bold" />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Short (3 chars)</label>
                                <input type="text" maxLength={3} value={teamShortName} onChange={e => setTeamShortName(e.target.value.toUpperCase())} className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-800 font-bold" />
                            </div>
                        </div>

                        <div className="mb-4">
                            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Primary Color</label>
                            <div className="flex gap-4 items-center">
