const StrategyToggle = ({ label, value, onChange }: { label: string, value: Strategy, onChange: (s: Strategy) => void }) => (
    <div className="flex flex-col items-center bg-slate-800/50 backdrop-blur rounded-xl p-2 flex-1">
        <span className="text-[8px] text-slate-400 uppercase font-black tracking-widest mb-1">{label}</span>
        <div className="flex bg-black/40 rounded-lg p-0.5 w-full">
            {(['defensive', 'balanced', 'attacking'] as Strategy[]).map(s => (
                <button
                    key={s}
                    onClick={() => onChange(s)}
                    className={`px-1 py-1.5 text-[8px] uppercase font-black rounded-md transition-all flex-1 ${value === s 
                        ? 'bg-teal-500 text-white shadow-lg scale-105' 
                        : 'text-slate-500 hover:text-slate-300'}`}
