const BroadcastScoreBar = ({ state, gameData, predictions }: { state: LiveMatchState, gameData: GameData, predictions: any }) => {
    const { battingTeam, bowlingTeam, innings, currentInningIndex, currentBatters, currentBowlerId, target } = state;
    const currentInning = innings[currentInningIndex];
    const striker = currentInning.batting.find(b => b.playerId === currentBatters.strikerId);
    const nonStriker = currentInning.batting.find(b => b.playerId === currentBatters.nonStrikerId);
    const bowler = currentInning.bowling.find(b => b.playerId === currentBowlerId);

    const batTeamData = gameData.allTeamsData.find(t => t.id === battingTeam.id);
    const bowlTeamData = gameData.allTeamsData.find(t => t.id === bowlingTeam.id);

    return (
        <div className="flex h-14 bg-[#111111] border-b-2 border-white/5 items-stretch overflow-hidden select-none font-sans italic tracking-tighter shadow-2xl">
            {/* L1: Batting Logo & Score */}
            <div className="flex items-center px-4 gap-3 relative min-w-[160px]" style={{ background: `linear-gradient(90deg, ${batTeamData?.primaryColor}44 0%, transparent 100%)` }}>
                <div className="w-8 h-8 flex-shrink-0 bg-white/10 rounded-lg p-1 border border-white/10 drop-shadow-lg" dangerouslySetInnerHTML={{__html: batTeamData?.logo || ''}} />
                <div className="flex flex-col">
                    <div className="flex items-baseline gap-1.5 leading-none">
                        <span className="text-lg font-black text-white">{batTeamData?.shortName}</span>
                        <span className="text-2xl font-black text-white">{currentInning.score}-{currentInning.wickets}</span>
                    </div>
                    <span className="text-[10px] font-black text-teal-400 mt-[-2px] tracking-widest uppercase">Over {currentInning.overs}</span>
                </div>
                <div className="absolute right-0 top-1/2 -translate-y-1/2 w-px h-8 bg-white/10" />
            </div>

            {/* L2: Batters */}
            <div className="flex flex-1 items-center px-4 gap-6">
                {[striker, nonStriker].map((b, idx) => (
                    <div key={idx} className={`flex items-center gap-3 transition-all ${idx === 0 ? 'opacity-100 scale-105' : 'opacity-40'}`}>
                        <div className="flex flex-col">
                            <span className="text-[11px] font-black text-slate-300 uppercase leading-none mb-0.5">{b?.playerName.split(' ').pop()}</span>
                            <div className="flex items-center gap-1.5">
                                <span className="text-xl font-black text-white">{b?.runs || 0}</span>
                                <span className="text-[10px] font-bold text-slate-500 mt-1">({b?.balls || 0})</span>
                            </div>
                        </div>
                        {idx === 0 && <span className="text-teal-500 font-black text-lg animate-pulse">★</span>}
                    </div>
                ))}
            </div>

            {/* L3: Bowler & Bowling Logo */}
            <div className="flex items-center px-4 gap-6 relative min-w-[180px]" style={{ background: `linear-gradient(-90deg, ${bowlTeamData?.primaryColor}44 0%, transparent 100%)` }}>
                <div className="absolute left-0 top-1/2 -translate-y-1/2 w-px h-8 bg-white/10" />
                <div className="flex flex-col text-right">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-wider mb-0.5">Bowling</span>
                    <div className="flex items-center justify-end gap-2">
                        <span className="text-xs font-black text-white truncate max-w-[80px]">{bowler?.playerName.split(' ').pop()}</span>
                        <span className="text-lg font-black text-teal-400">{bowler?.wickets}-{bowler?.runsConceded}</span>
                        <span className="text-[10px] font-bold text-slate-500 mt-1">({bowler?.overs})</span>
                    </div>
                </div>
                <div className="w-8 h-8 flex-shrink-0 bg-white/10 rounded-lg p-1 border border-white/10 drop-shadow-lg" dangerouslySetInnerHTML={{__html: bowlTeamData?.logo || ''}} />
            </div>
        </div>
    );
};

