import React from 'react';
import { GameData, Team, CareerScreen } from '../types';
import { Icons } from './Icons';
import { SPONSOR_THRESHOLDS, TOURNAMENT_LOGOS } from '../data';

interface DashboardProps {
    gameData: GameData;
    userTeam: Team | null;
    setScreen: (screen: CareerScreen) => void;
    handlePlayMatch: () => void;
    handleForwardDay: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ gameData, userTeam, setScreen, handlePlayMatch, handleForwardDay }) => {
    const currentSchedule = gameData.schedule[gameData.currentFormat];
    const matchIndex = gameData.currentMatchIndex[gameData.currentFormat];
    const sponsorship = gameData.sponsorships?.[gameData.currentFormat];
    const popularity = gameData.popularity || 0;
    const currentThresholds = SPONSOR_THRESHOLDS[gameData.currentFormat] || {};

    if (matchIndex >= currentSchedule.length) {
        return (
            <div className="p-4 text-center h-full flex flex-col items-center justify-center bg-[#101817]">
                <div className="w-20 h-20 text-teal-500 mb-4 animate-bounce"><Icons.Trophy /></div>
                <p className="text-xl font-black italic uppercase tracking-tighter">Tournament Finished</p>
                <button onClick={() => setScreen('END_OF_FORMAT')} className="mt-4 px-8 py-3 bg-teal-500 rounded-xl font-bold">PROCEED</button>
            </div>
        );
    }

    let nextMatch = { ...currentSchedule[matchIndex] };
    const isUserMatch = userTeam ? (nextMatch.teamA === userTeam.name || nextMatch.teamB === userTeam.name) : false;

    const renderTournamentLogo = () => {
        if (sponsorship?.tournamentLogo) {
            return <div className={`w-12 h-12 mx-auto mb-2 ${sponsorship.logoColor}`} dangerouslySetInnerHTML={{__html: sponsorship.tournamentLogo}}></div>;
        }
        return <div className="w-12 h-12 mx-auto mb-2 text-slate-300" dangerouslySetInnerHTML={{__html: TOURNAMENT_LOGOS[0].svg}}></div>;
    };

    return (
        <div className="p-4 space-y-6 bg-[#101817] min-h-full font-sans">
            <header className="text-center py-6 bg-gradient-to-b from-slate-900/50 to-transparent rounded-3xl border border-white/5">
                <p className="text-[10px] font-black text-teal-500 tracking-[0.4em] mb-2 uppercase">Season {gameData.currentSeason}</p>
                {renderTournamentLogo()}
                <h1 className={`text-3xl mt-1 ${sponsorship?.logoColor || 'text-teal-500'} font-black italic tracking-tighter uppercase drop-shadow-[0_0_10px_rgba(0,0,0,0.5)]`}>
                    {sponsorship?.sponsorName} {sponsorship?.tournamentName}
                </h1>
                <p className="text-sm font-bold text-slate-400 mt-2">Managing {userTeam?.name}</p>
            </header>

            <div className="bg-white/5 backdrop-blur-xl rounded-[40px] p-8 border border-white/10 shadow-2xl relative overflow-hidden group">
                <div className="absolute top-0 left-0 w-full h-1 bg-teal-500 shadow-[0_0_15px_teal]" />
                <h3 className="font-black text-xs mb-6 text-center text-teal-400 uppercase tracking-widest">Incoming Encounter</h3>
                <div className="flex justify-between items-center gap-4 text-center">
                    <div className="flex-1">
                        <div className="text-2xl font-black italic tracking-tighter truncate">{nextMatch.teamA}</div>
                    </div>
                    <div className="text-teal-500 font-black italic text-xl">VS</div>
                    <div className="flex-1">
                        <div className="text-2xl font-black italic tracking-tighter truncate">{nextMatch.teamB}</div>
                    </div>
                </div>

                {isUserMatch ? (
                    <button onClick={handlePlayMatch} className="mt-8 w-full bg-teal-500 hover:bg-teal-400 text-white font-black py-5 px-4 rounded-2xl shadow-[0_10px_30px_rgba(20,184,166,0.3)] flex items-center justify-center space-x-3 transition-all active:scale-95 italic text-xl tracking-tighter">
                        <Icons.PlayMatch />
                        <span>PLAY MATCH</span>
                    </button>
                ) : (
                    <button onClick={handleForwardDay} className="mt-8 w-full bg-slate-800 hover:bg-slate-700 text-white font-black py-5 px-4 rounded-2xl flex items-center justify-center space-x-3 transition-all active:scale-95 uppercase tracking-widest text-xs">
                        <span>Simulate Day</span>
                    </button>
                )}
            </div>

            <div className="bg-slate-900 rounded-3xl p-6 border border-white/5">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="font-black text-[10px] uppercase text-slate-500 tracking-widest">Sponsorship Board</h3>
                    <div className="bg-yellow-500/10 text-yellow-500 font-black px-3 py-1 rounded-lg text-xs border border-yellow-500/20">
                        {popularity} Popularity ★
                    </div>
                </div>

                <div className="space-y-4">
                    {Object.entries(currentThresholds).map(([name, threshold]) => {
                        const progress = Math.min(100, (popularity / threshold) * 100);
                        const isUnlocked = popularity >= threshold;
                        return (
                            <div key={name} className={isUnlocked ? 'opacity-100' : 'opacity-30'}>
                                <div className="flex justify-between text-[10px] font-black uppercase mb-1.5">
                                    <span className={isUnlocked ? 'text-teal-400' : 'text-slate-500'}>{name}</span>
                                    <span className="text-slate-500">{popularity} / {threshold}</span>
                                </div>
                                <div className="h-1 bg-white/5 rounded-full overflow-hidden">
                                    <div className={`h-full transition-all duration-1000 ${isUnlocked ? 'bg-teal-500' : 'bg-slate-700'}`} style={{ width: `${progress}%` }} />
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            <div className="grid grid-cols-3 gap-3 pb-8">
                 {[
                    { s: 'LEAGUES', l: 'Standings', i: <Icons.Leagues /> },
                    { s: 'NEWS', l: 'Journal', i: <Icons.News /> },
                    { s: 'LINEUPS', l: 'Lineups', i: <Icons.Lineups /> },
                    { s: 'EDITOR', l: 'Editor', i: <Icons.Editor /> },
                    { s: 'TRANSFERS', l: 'Market', i: <Icons.Transfers /> },
                    { s: 'COMPARISON', l: 'Compare', i: <Icons.Compare /> }
                 ].map(btn => (
                    <button key={btn.s} onClick={() => setScreen(btn.s as any)} className="bg-white/5 p-4 rounded-2xl flex flex-col items-center justify-center space-y-2 hover:bg-white/10 transition-all border border-white/5 group">
                        <div className="text-slate-400 group-hover:text-teal-400 transition-colors">{btn.i}</div>
                        <span className="font-black text-[10px] uppercase tracking-widest text-slate-500 group-hover:text-slate-300">{btn.l}</span>
                    </button>
                 ))}
            </div>
        </div>
    );
};

export default Dashboard;

import React, { useState } from 'react';
import { GameData, Brand, TVChannel } from '../types';
import { Icons } from './Icons';

interface CustomizationHubProps {
    gameData: GameData;
    setGameData: React.Dispatch<React.SetStateAction<GameData | null>>;
}

const CustomizationHub: React.FC<CustomizationHubProps> = ({ gameData, setGameData }) => {
    const [activeTab, setActiveTab] = useState<'teams' | 'brands' | 'tv'>('teams');
    const [selectedTeamId, setSelectedTeamId] = useState(gameData.teams[0].id);

    const teamData = gameData.allTeamsData.find(t => t.id === selectedTeamId)!;

    // Team Edit State
    const [teamName, setTeamName] = useState(teamData.name);
    const [teamShortName, setTeamShortName] = useState(teamData.shortName);
    const [teamLogo, setTeamLogo] = useState(teamData.logo);
    const [primaryColor, setPrimaryColor] = useState(teamData.primaryColor);
    const [secondaryColor, setSecondaryColor] = useState(teamData.secondaryColor);

    const handleTeamUpdate = () => {
        setGameData(prev => {
            if (!prev) return null;
            const newAllTeamsData = prev.allTeamsData.map(t => {
                if (t.id === selectedTeamId) {
                    return { ...t, name: teamName, shortName: teamShortName, logo: teamLogo, primaryColor, secondaryColor };
                }
                return t;
            });
            const newTeams = prev.teams.map(t => {
                if (t.id === selectedTeamId) {
                    return { ...t, name: teamName, shortName: teamShortName, primaryColor, secondaryColor };
                }
                return t;
            });
            return { ...prev, allTeamsData: newAllTeamsData, teams: newTeams };
        });
    };

    return (
        <div className="p-4 h-[calc(100vh-90px)] overflow-y-auto bg-slate-50 dark:bg-[#101817] flex flex-col font-sans">
            <h2 className="text-3xl font-black italic text-center mb-6 text-slate-800 dark:text-white uppercase tracking-tighter">Identity Studio</h2>

            <div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-xl gap-1 mb-6">
                {['teams', 'brands', 'tv'].map(tab => (
                    <button
                        key={tab}
                        onClick={() => setActiveTab(tab as any)}
                        className={`flex-1 py-2 rounded-lg text-xs font-black uppercase transition-all ${activeTab === tab ? 'bg-teal-500 text-white shadow' : 'text-slate-500 hover:text-slate-700'}`}
                    >
                        {tab}
                    </button>
                ))}
            </div>

            {activeTab === 'teams' && (
                <div className="space-y-6 animate-fade-in pb-10">
                    <div className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800">
                        <div className="mb-4">
                            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Select Franchise</label>
                            <select 
                                value={selectedTeamId} 
                                onChange={e => {
                                    const tid = e.target.value;
                                    const t = gameData.allTeamsData.find(x => x.id === tid)!;
                                    setSelectedTeamId(tid);
                                    setTeamName(t.name);
                                    setTeamShortName(t.shortName);
                                    setTeamLogo(t.logo);
                                    setPrimaryColor(t.primaryColor);
                                    setSecondaryColor(t.secondaryColor);
                                }}
                                className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-800 border-none font-bold text-lg"
                            >
                                {gameData.teams.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                            </select>
                        </div>

                        <div className="grid grid-cols-2 gap-4 mb-4">
                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Name</label>
                                <input type="text" value={teamName} onChange={e => setTeamName(e.target.value)} className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-800 font-bold" />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Short (3 chars)</label>
                                <input type="text" maxLength={3} value={teamShortName} onChange={e => setTeamShortName(e.target.value.toUpperCase())} className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-800 font-bold" />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4 mb-4">
                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Primary Color</label>
                                <div className="flex gap-2 items-center bg-slate-50 dark:bg-slate-800 p-2 rounded-2xl">
                                    <input type="color" value={primaryColor} onChange={e => setPrimaryColor(e.target.value)} className="h-10 w-10 rounded-xl border-none p-0 overflow-hidden cursor-pointer" />
                                    <div className="text-[10px] font-mono text-slate-500 uppercase">{primaryColor}</div>
                                </div>
                            </div>
                            <div>
                                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Secondary Color</label>
                                <div className="flex gap-2 items-center bg-slate-50 dark:bg-slate-800 p-2 rounded-2xl">
                                    <input type="color" value={secondaryColor} onChange={e => setSecondaryColor(e.target.value)} className="h-10 w-10 rounded-xl border-none p-0 overflow-hidden cursor-pointer" />
                                    <div className="text-[10px] font-mono text-slate-500 uppercase">{secondaryColor}</div>
                                </div>
                            </div>
                        </div>

                        <div className="mb-6">
                            <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Logo SVG Source</label>
                            <textarea value={teamLogo} onChange={e => setTeamLogo(e.target.value)} className="w-full p-4 rounded-2xl bg-slate-50 dark:bg-slate-800 text-xs font-mono h-32 border-none" />
                        </div>

                        <div className="flex items-center gap-6 p-6 bg-slate-100 dark:bg-slate-950 rounded-[40px] mb-6 border-2 border-dashed border-slate-300 dark:border-slate-800">
                            <div className="w-24 h-24 p-2 bg-white rounded-3xl shadow-lg flex items-center justify-center overflow-hidden" dangerouslySetInnerHTML={{__html: teamLogo}}></div>
                            <div>
                                <h4 className="text-2xl font-black italic tracking-tighter" style={{ color: primaryColor }}>{teamName}</h4>
                                <span className="text-xs font-bold text-slate-500 uppercase tracking-widest">{teamShortName}</span>
                            </div>
                        </div>

                        <button onClick={handleTeamUpdate} className="w-full py-5 rounded-2xl bg-teal-500 hover:bg-teal-400 text-white font-black uppercase italic tracking-widest shadow-xl transition-all active:scale-95">Save Changes</button>
                    </div>
                </div>
            )}

            {activeTab === 'brands' && (
                <div className="p-4 text-center text-slate-500">Custom Brands coming soon to the Marketplace.</div>
            )}
        </div>
    );
};

export default CustomizationHub;

