const BroadcastScoreBar = ({ state, gameData }: { state: LiveMatchState, gameData: GameData }) => {
    const { battingTeam, bowlingTeam, innings, currentInningIndex, currentBatters, currentBowlerId } = state;
    const currentInning = innings[currentInningIndex];
    const striker = currentInning.batting.find(b => b.playerId === currentBatters.strikerId);
    const nonStriker = currentInning.batting.find(b => b.playerId === currentBatters.nonStrikerId);
    const bowler = currentInning.bowling.find(b => b.playerId === currentBowlerId);

    const batTeamData = gameData.allTeamsData.find(t => t.id === battingTeam.id);
    const bowlTeamData = gameData.allTeamsData.find(t => t.id === bowlingTeam.id);

    return (
        <div className="flex h-16 bg-[#111111] border-b-2 border-white/10 items-stretch overflow-hidden select-none font-sans italic tracking-tighter shadow-2xl relative">
            {/* Left Section: Batting Team Branding & Main Score */}
            <div 
                className="flex items-center px-4 gap-4 relative min-w-[240px]" 
                style={{ background: `linear-gradient(90deg, ${batTeamData?.primaryColor}dd 0%, transparent 100%)` }}
            >
                <div className="w-12 h-12 flex-shrink-0 bg-white/20 rounded-xl p-1.5 border border-white/20 drop-shadow-xl" dangerouslySetInnerHTML={{__html: batTeamData?.logo || ''}} />
                <div className="flex flex-col">
                    <div className="flex items-baseline gap-2 leading-none">
                        <span className="text-xl font-black text-white">{batTeamData?.shortName}</span>
                        <span className="text-3xl font-black text-white">{currentInning.score}-{currentInning.wickets}</span>
                    </div>
                    <div className="bg-black/60 px-2 py-0.5 rounded-full w-fit mt-1">
                        <span className="text-[10px] font-black text-teal-400 tracking-[0.2em] uppercase">Over {currentInning.overs}</span>
                    </div>
                </div>
                <div className="absolute right-0 top-1/2 -translate-y-1/2 w-px h-10 bg-white/10" />
            </div>

            {/* Middle Section: Both Batters */}
            <div className="flex flex-1 items-center px-8 gap-10 bg-black/30">
                {[striker, nonStriker].map((b, idx) => (
                    <div key={idx} className={`flex items-center gap-4 transition-all duration-500 ${idx === 0 ? 'opacity-100 scale-105' : 'opacity-40'}`}>
                        <div className="flex flex-col min-w-[110px]">
                            <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">{idx === 0 ? 'STRIKING' : 'NON-STRIKER'}</span>
                            <span className="text-sm font-black text-white uppercase truncate max-w-[100px]">{b?.playerName.split(' ').pop()}</span>
                            <div className="flex items-baseline gap-2">
                                <span className="text-2xl font-black text-white">{b?.runs || 0}</span>
                                <span className="text-[11px] font-bold text-slate-500">({b?.balls || 0})</span>
                            </div>
                        </div>
                        {idx === 0 && (
                            <div className="w-2.5 h-2.5 bg-yellow-400 rounded-full animate-pulse shadow-[0_0_12px_yellow]" />
                        )}
                    </div>
                ))}
            </div>

            {/* Right Section: Bowler & Bowling Team Identity */}
            <div 
                className="flex items-center px-4 gap-6 relative min-w-[280px]" 
                style={{ background: `linear-gradient(-90deg, ${bowlTeamData?.primaryColor}dd 0%, transparent 100%)` }}
            >
                <div className="absolute left-0 top-1/2 -translate-y-1/2 w-px h-10 bg-white/10" />
                <div className="flex flex-col text-right flex-grow">
                    <span className="text-[10px] font-black text-slate-200 uppercase tracking-widest mb-1">CURRENT BOWLER</span>
