                                {[...Array(6)].map((_, i) => {
                                    const ballInOver = Math.floor((bowler?.ballsBowled || 0) % 6);
                                    return <div key={i} className={`h-1 w-2.5 rounded-full ${i < ballInOver ? 'bg-teal-400' : 'bg-white/20'}`} />
