                        </div>
                    </div>
                </div>
                <div className="w-12 h-12 flex-shrink-0 bg-white/20 rounded-xl p-1.5 border border-white/20 drop-shadow-xl" dangerouslySetInnerHTML={{__html: bowlTeamData?.logo || ''}} />
