                        <div className="space-y-6">
                            {state.waitingFor === 'batter' && (
                                <select className="w-full p-6 rounded-[2rem] bg-zinc-800 border-none font-black text-lg focus:ring-4 focus:ring-teal-500/50 appearance-none text-center" onChange={e => selectNextBatter(e.target.value)}>
                                    <option>Select New Batter</option>
