                                </select>
                            )}
                            {state.waitingFor === 'bowler' && (
                                <select className="w-full p-6 rounded-[2rem] bg-zinc-800 border-none font-black text-lg focus:ring-4 focus:ring-teal-500/50 appearance-none text-center" onChange={e => selectNextBowler(e.target.value)}>
                                    <option>Select New Bowler</option>
                                    {state.innings[state.currentInningIndex].bowling.filter(p => p.playerId !== state.currentBowlerId).map(p => <option key={p.playerId} value={p.playerId}>{p.playerName.toUpperCase()} ({p.overs})</option>)}
                                </select>
                            )}
                            <button onClick={() => {}} className="w-full bg-teal-600 hover:bg-teal-500 py-6 rounded-[2rem] font-black text-white shadow-2xl uppercase italic tracking-[0.2em] text-xl transition-all">Confirm</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

