import React from 'react';
import { GameData, Team, CareerScreen } from '../types';
import { Icons } from './Icons';
import { SPONSOR_THRESHOLDS, TOURNAMENT_LOGOS } from '../data';

interface DashboardProps {
    gameData: GameData;
    userTeam: Team | null;
    setScreen: (screen: CareerScreen) => void;
    handlePlayMatch: () => void;
    handleForwardDay: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ gameData, userTeam, setScreen, handlePlayMatch, handleForwardDay }) => {
    const currentSchedule = gameData.schedule[gameData.currentFormat];
    const matchIndex = gameData.currentMatchIndex[gameData.currentFormat];
    const sponsorship = gameData.sponsorships?.[gameData.currentFormat];
    const popularity = gameData.popularity || 0;
    const currentThresholds = SPONSOR_THRESHOLDS[gameData.currentFormat] || {};

    if (matchIndex >= currentSchedule.length) {
        return (
            <div className="p-4 text-center h-full flex flex-col items-center justify-center bg-[#101817]">
                <div className="w-20 h-20 text-teal-500 mb-6 animate-bounce"><Icons.Trophy /></div>
                <p className="text-2xl font-black italic uppercase tracking-tighter text-white">Tournament Finished</p>
                <button onClick={() => setScreen('END_OF_FORMAT')} className="mt-8 px-10 py-4 bg-teal-500 rounded-[2rem] font-black text-white italic tracking-widest shadow-xl">PROCEED</button>
            </div>
        );
    }

    let nextMatch = { ...currentSchedule[matchIndex] };
    const isUserMatch = userTeam ? (nextMatch.teamA === userTeam.name || nextMatch.teamB === userTeam.name) : false;

    const renderTournamentLogo = () => {
        if (sponsorship?.tournamentLogo) {
            return <div className={`w-14 h-14 mx-auto mb-3 ${sponsorship.logoColor} drop-shadow-lg`} dangerouslySetInnerHTML={{__html: sponsorship.tournamentLogo}}></div>;
        }
        return <div className="w-14 h-14 mx-auto mb-3 text-slate-500" dangerouslySetInnerHTML={{__html: TOURNAMENT_LOGOS[0].svg}}></div>;
    };

    return (
        <div className="p-4 space-y-6 bg-[#0c1211] min-h-full font-sans overflow-y-auto">
            <header className="text-center py-8 bg-gradient-to-b from-slate-900/80 to-transparent rounded-[3rem] border border-white/5 shadow-2xl">
                <p className="text-[10px] font-black text-teal-500 tracking-[0.5em] mb-3 uppercase">SEASON {gameData.currentSeason}</p>
                {renderTournamentLogo()}
                <h1 className={`text-4xl mt-1 ${sponsorship?.logoColor || 'text-teal-500'} font-black italic tracking-tighter uppercase drop-shadow-[0_0_15px_rgba(0,0,0,0.8)]`}>
                    {sponsorship?.sponsorName} {sponsorship?.tournamentName}
                </h1>
                <p className="text-sm font-bold text-slate-400 mt-3 tracking-widest">MANAGER: {userTeam?.name.toUpperCase()}</p>
            </header>

            <div className="bg-white/5 backdrop-blur-3xl rounded-[3rem] p-10 border border-white/10 shadow-[0_20px_50px_rgba(0,0,0,0.5)] relative overflow-hidden group">
                <div className="absolute top-0 left-0 w-full h-1.5 bg-teal-500 shadow-[0_0_25px_teal]" />
                <h3 className="font-black text-[10px] mb-8 text-center text-teal-400 uppercase tracking-[0.3em]">INCOMING ENCOUNTER</h3>
                <div className="flex justify-between items-center gap-6 text-center">
                    <div className="flex-1">
                        <div className="text-2xl font-black italic tracking-tighter text-white truncate uppercase">{nextMatch.teamA}</div>
                    </div>
                    <div className="text-teal-500 font-black italic text-2xl animate-pulse">VS</div>
                    <div className="flex-1">
                        <div className="text-2xl font-black italic tracking-tighter text-white truncate uppercase">{nextMatch.teamB}</div>
                    </div>
                </div>

                {isUserMatch ? (
                    <button onClick={handlePlayMatch} className="mt-10 w-full bg-teal-600 hover:bg-teal-500 text-white font-black py-6 px-6 rounded-[2rem] shadow-[0_15px_40px_rgba(20,184,166,0.4)] flex items-center justify-center space-x-4 transition-all active:scale-95 italic text-2xl tracking-tighter">
                        <Icons.PlayMatch />
                        <span>START MATCH</span>
                    </button>
                ) : (
                    <button onClick={handleForwardDay} className="mt-10 w-full bg-zinc-800 hover:bg-zinc-700 text-white font-black py-6 px-6 rounded-[2rem] flex items-center justify-center space-x-4 transition-all active:scale-95 uppercase tracking-[0.2em] text-xs">
                        <span>Advance Schedule</span>
                    </button>
                )}
            </div>

            {/* Sponsorship Board */}
            <div className="bg-zinc-900 rounded-[3rem] p-8 border border-white/5 shadow-xl">
                <div className="flex justify-between items-center mb-8">
                    <h3 className="font-black text-[10px] uppercase text-zinc-500 tracking-[0.4em]">SPONSORSHIP DEALS</h3>
                    <div className="bg-yellow-500/10 text-yellow-500 font-black px-4 py-1.5 rounded-full text-xs border border-yellow-500/20 shadow-lg">
                        {popularity} REPUTATION ★
                    </div>
                </div>

                <div className="space-y-6">
                    {Object.entries(currentThresholds).map(([name, threshold]) => {
                        const progress = Math.min(100, (popularity / (threshold as number)) * 100);
                        const isUnlocked = popularity >= (threshold as number);
                        return (
                            <div key={name} className={`transition-opacity duration-500 ${isUnlocked ? 'opacity-100' : 'opacity-20'}`}>
                                <div className="flex justify-between text-[11px] font-black uppercase mb-2.5 tracking-widest">
                                    <span className={isUnlocked ? 'text-teal-400' : 'text-zinc-500'}>{name}</span>
                                    <span className="text-zinc-500">{popularity} / {threshold as number}</span>
                                </div>
                                <div className="h-2 bg-white/5 rounded-full overflow-hidden shadow-inner">
                                    <div className={`h-full transition-all duration-1000 ${isUnlocked ? 'bg-teal-500 shadow-[0_0_10px_teal]' : 'bg-zinc-800'}`} style={{ width: `${progress}%` }} />
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            <div className="grid grid-cols-3 gap-4 pb-12">
                 {[
                    { s: 'LEAGUES', l: 'Podium', i: <Icons.Leagues /> },
                    { s: 'NEWS', l: 'Global', i: <Icons.News /> },
                    { s: 'LINEUPS', l: 'Roster', i: <Icons.Lineups /> },
                    { s: 'EDITOR', l: 'Lab', i: <Icons.Editor /> },
                    { s: 'TRANSFERS', l: 'Trade', i: <Icons.Transfers /> },
                    { s: 'COMPARISON', l: 'Vs', i: <Icons.Compare /> }
                 ].map(btn => (
                    <button key={btn.s} onClick={() => setScreen(btn.s as any)} className="bg-white/5 p-6 rounded-[2rem] flex flex-col items-center justify-center space-y-3 hover:bg-white/10 transition-all border border-white/5 group shadow-lg">
                        <div className="text-zinc-500 group-hover:text-teal-400 transition-colors transform group-hover:scale-110 duration-300">{btn.i}</div>
                        <span className="font-black text-[9px] uppercase tracking-[0.2em] text-zinc-500 group-hover:text-zinc-300">{btn.l}</span>
                    </button>
                 ))}
            </div>
        </div>
    );
};

