import React, { useState, useEffect } from 'react';
import { AppState, GameData, Team, Format, MatchResult, Standing } from './types';
import { PLAYERS, TEAMS, GROUNDS, PRE_BUILT_SQUADS, INITIAL_SPONSORSHIPS, INITIAL_NEWS } from './data';
import { LoadingSpinner, generateLeagueSchedule } from './utils';

// Components
import MainMenu from './components/MainMenu';
import TeamSelection from './components/TeamSelection';
import CareerHub from './components/CareerHub';

export const MAX_SQUAD_SIZE = 20;
export const MIN_SQUAD_SIZE = 15;
export const MAX_FOREIGN_PLAYERS = 3;

export const App = () => {
  const [appState, setAppState] = useState<AppState>('MAIN_MENU');
  const [gameData, setGameData] = useState<GameData | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState<'light' | 'dark'>('dark');
  const [feedbackMessage, setFeedbackMessage] = useState<{ text: string; type: 'success' | 'error' } | null>(null);
  const [hasSaveData, setHasSaveData] = useState(false);

  useEffect(() => {
    const savedTheme = localStorage.getItem('cricketManagerTheme') || 'dark';
    setTheme(savedTheme as 'light' | 'dark');
    const savedGame = localStorage.getItem('cricketManagerSave');
    if (savedGame) {
        setHasSaveData(true);
    }
    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (theme === 'light') {
        document.documentElement.classList.remove('dark');
    } else {
        document.documentElement.classList.add('dark');
    }
    localStorage.setItem('cricketManagerTheme', theme);
  }, [theme]);

  useEffect(() => {
    if (gameData && !isLoading) {
      localStorage.setItem('cricketManagerSave', JSON.stringify(gameData));
      setHasSaveData(true);
    }
  }, [gameData, isLoading]);

  const showFeedback = (text: string, type: 'success' | 'error' = 'success') => {
    setFeedbackMessage({ text, type });
    setTimeout(() => setFeedbackMessage(null), 2500);
  };

  const saveGame = () => {
    showFeedback("Progress is saved automatically!");
  };

  const loadGame = () => {
    if (window.confirm("Loading a saved game will overwrite your current unsaved progress. Continue?")) {
        const savedGame = localStorage.getItem('cricketManagerSave');
        if (savedGame) {
            try {
                setGameData(JSON.parse(savedGame));
                showFeedback("Game Loaded!", "success");
                setAppState('CAREER_HUB');
            } catch (e) {
                console.error("Failed to parse saved game data during load:", e);
                localStorage.removeItem('cricketManagerSave');
                setHasSaveData(false);
                showFeedback("Failed to load saved game. It may be corrupt.", "error");
            }
        } else {
            showFeedback("No saved game found.", "error");
        }
    }
  };

  const resumeGame = () => {
    const savedGame = localStorage.getItem('cricketManagerSave');
    if (savedGame) {
        try {
            setGameData(JSON.parse(savedGame));
            setAppState('CAREER_HUB');
            showFeedback("Game Resumed!", "success");
        } catch(e) {
            console.error("Failed to parse saved game data:", e);
            localStorage.removeItem('cricketManagerSave');
            setHasSaveData(false);
            showFeedback("Failed to load saved game. It may be corrupt.", "error");
        }
    }
  };

  const handleStartNewGame = () => {
    if (hasSaveData && !window.confirm("Starting a new game will overwrite your saved progress. Are you sure?")) {
        return;
    }
    setAppState('TEAM_SELECTION');
  };

  const initializeNewGame = (userTeamId: string) => {
    setIsLoading(true);
    const allPlayers = PLAYERS.map(p => JSON.parse(JSON.stringify(p)));
    const initialTeamsData = [...TEAMS];
    const allPlayersById = new Map(allPlayers.map(p => [p.id, p]));

    const initialTeams: Team[] = initialTeamsData.map(teamData => {
        const squadPlayerIds = PRE_BUILT_SQUADS[teamData.id];
        if (!squadPlayerIds) {
             console.warn(`Squad not found for team ID: ${teamData.id}, creating empty squad.`);
             // Fixed: Added missing properties (shortName, primaryColor, secondaryColor) to satisfy Team interface.
             return { id: teamData.id, name: teamData.name, shortName: teamData.shortName, primaryColor: teamData.primaryColor, secondaryColor: teamData.secondaryColor, squad: [], captains: {} };
        }
        const squad = squadPlayerIds.map(playerId => {
            const player = allPlayersById.get(playerId);
            if (!player) {
               console.warn(`Player with ID ${playerId} not found for team ${teamData.name}.`);
               return null;
            }
            return JSON.parse(JSON.stringify(player));
        }).filter(Boolean) as any; 
        // Fixed: Added missing properties (shortName, primaryColor, secondaryColor) to satisfy Team interface.
        return { id: teamData.id, name: teamData.name, shortName: teamData.shortName, primaryColor: teamData.primaryColor, secondaryColor: teamData.secondaryColor, squad: squad, captains: {} };
    });

    const initialStandings = (teams: Team[]) => teams.map(team => ({ 
        teamId: team.id, teamName: team.name, played: 0, won: 0, lost: 0, drawn: 0, points: 0, netRunRate: 0, runsFor: 0, runsAgainst: 0 
    }));

    const mainTeams = initialTeams.filter((t, i) => !initialTeamsData[i].isDevelopmentTeam);
    const devTeams = initialTeams.filter((t, i) => initialTeamsData[i].isDevelopmentTeam);

    const schedules = {
        [Format.T20]: generateLeagueSchedule(mainTeams, Format.T20),
        [Format.ODI]: generateLeagueSchedule(mainTeams, Format.ODI),
        [Format.FIRST_CLASS]: generateLeagueSchedule(mainTeams, Format.FIRST_CLASS),
        [Format.DEVELOPMENT_T20]: generateLeagueSchedule(devTeams, Format.DEVELOPMENT_T20),
        [Format.DEVELOPMENT_ODI]: generateLeagueSchedule(devTeams, Format.DEVELOPMENT_ODI),
        [Format.DEVELOPMENT_FIRST_CLASS]: generateLeagueSchedule(devTeams, Format.DEVELOPMENT_FIRST_CLASS),
        [Format.RISE_T20]: generateLeagueSchedule(devTeams, Format.RISE_T20),
        [Format.RISE_ODI]: generateLeagueSchedule(devTeams, Format.RISE_ODI),
        [Format.RISE_FIRST_CLASS]: generateLeagueSchedule(devTeams, Format.RISE_FIRST_CLASS),
    };

    const newGameData: GameData = {
      userTeamId,
      teams: initialTeams,
      grounds: [...GROUNDS],
      allTeamsData: initialTeamsData,
      allPlayers,
      schedule: schedules,
      currentMatchIndex: {
        [Format.T20]: 0,
        [Format.ODI]: 0,
        [Format.FIRST_CLASS]: 0,
        [Format.DEVELOPMENT_T20]: 0,
        [Format.DEVELOPMENT_ODI]: 0,
        [Format.DEVELOPMENT_FIRST_CLASS]: 0,
        [Format.RISE_T20]: 0,
        [Format.RISE_ODI]: 0,
        [Format.RISE_FIRST_CLASS]: 0,
      },
      standings: {
        [Format.T20]: initialStandings(mainTeams),
        [Format.ODI]: initialStandings(mainTeams),
        [Format.FIRST_CLASS]: initialStandings(mainTeams),
        [Format.DEVELOPMENT_T20]: initialStandings(devTeams),
        [Format.DEVELOPMENT_ODI]: initialStandings(devTeams),
        [Format.DEVELOPMENT_FIRST_CLASS]: initialStandings(devTeams),
        [Format.RISE_T20]: initialStandings(devTeams),
        [Format.RISE_ODI]: initialStandings(devTeams),
        [Format.RISE_FIRST_CLASS]: initialStandings(devTeams),
      },
      matchResults: Object.values(Format).reduce((acc, format) => {
        acc[format] = [];
        return acc;
      }, {} as Record<Format, MatchResult[]>),
      playingXIs: {},
      currentSeason: 1,
      currentFormat: Format.T20, 
      awardsHistory: [],
      scoreLimits: {},
      records: {
        batterVsBowler: [],
        teamVsTeam: [],
        playerVsTeam: [],
      },
      promotionHistory: [],
      popularity: 50,
      sponsorships: INITIAL_SPONSORSHIPS,
      news: INITIAL_NEWS,
      activeMatch: null,
    };
    setGameData(newGameData);
    setAppState('CAREER_HUB');
    setIsLoading(false);
  };

  const resetGame = () => {
      if (window.confirm("Are you sure you want to reset all progress? This action cannot be undone.")) {
          localStorage.removeItem('cricketManagerSave');
          setGameData(null);
          setAppState('MAIN_MENU');
          setHasSaveData(false);
          showFeedback("Game Reset Successfully.", "success");
      }
  };

  const renderContent = () => {
    if (isLoading) {
        return (
            <div className="bg-white dark:bg-gray-900 h-full flex items-center justify-center">
                <LoadingSpinner />
            </div>
        );
    }
    switch(appState) {
        case 'MAIN_MENU':
            return <MainMenu onStartNewGame={handleStartNewGame} onResumeGame={resumeGame} hasSaveData={hasSaveData} />;
        case 'TEAM_SELECTION':
            return <TeamSelection onTeamSelected={initializeNewGame} theme={theme} />;
        case 'CAREER_HUB':
            if (gameData) {
                return <CareerHub gameData={gameData} setGameData={setGameData} onResetGame={resetGame} theme={theme} setTheme={setTheme} saveGame={saveGame} loadGame={loadGame} showFeedback={showFeedback} />;
            }
            setAppState('MAIN_MENU');
            return null;
        default:
            return <div>Unknown App State</div>;
    }
  }

  return (
    <div className="bg-gray-100 dark:bg-gray-900 min-h-screen flex items-center justify-center font-sans">
      <div className="w-full max-w-md h-screen max-h-[932px] bg-gray-50 dark:bg-[#2C3531] border-4 border-gray-300 dark:border-gray-700 rounded-[60px] shadow-2xl shadow-black/50 overflow-hidden relative text-gray-900 dark:text-gray-200 flex flex-col">
        {renderContent()}
        {feedbackMessage && (
            <div className={`absolute bottom-28 left-1/2 -translate-x-1/2 px-4 py-2 rounded-lg z-50 shadow-lg text-white font-semibold ${feedbackMessage.type === 'success' ? 'bg-green-500' : 'bg-red-500'}`}>
                {feedbackMessage.text}
            </div>
        )}
      </div>
    </div>
  );
};

export enum Format {
    T20 = 'Premier T20 League',
    ODI = 'Premier One-Day Cup',
    FIRST_CLASS = 'Premier First-Class Shield',
    DEVELOPMENT_T20 = 'Development T20 Cup',
    DEVELOPMENT_ODI = 'Development List-A Cup',
    DEVELOPMENT_FIRST_CLASS = 'Development First-Class Cup',
    RISE_T20 = 'Rise T20 Cup',
    RISE_ODI = 'Rise List-A Cup',
    RISE_FIRST_CLASS = 'Rise First-Class Cup'
}

export enum PlayerRole {
    BATSMAN = 'BT',
    WICKET_KEEPER = 'WK',
    ALL_ROUNDER = 'AR',
    SPIN_BOWLER = 'SB',
    FAST_BOWLER = 'BL',
}

export type BattingStyle = 'A' | 'D' | 'N' | 'NA';
export type Strategy = 'defensive' | 'balanced' | 'attacking';
export type AppState = 'MAIN_MENU' | 'TEAM_SELECTION' | 'CAREER_HUB';
export type CareerScreen = 'DASHBOARD' | 'LEAGUES' | 'LINEUPS' | 'EDITOR' | 'NEWS' | 'STATS' | 'SETTINGS' | 'PLAYER_PROFILE' | 'MATCH_RESULT' | 'FORWARD_RESULTS' | 'AWARDS_RECORDS' | 'TRANSFERS' | 'END_OF_FORMAT' | 'COMPARISON' | 'SCHEDULE' | 'LIVE_MATCH' | 'SPONSOR_ROOM' | 'CUSTOMIZATION' | 'SELECT_PLAYER_FOR_COMPARISON_SLOT_1' | 'SELECT_PLAYER_FOR_COMPARISON_SLOT_2';

export interface PlayerStats {
    matches: number; runs: number; highestScore: number; average: number; strikeRate: number; ballsFaced: number; dismissals: number;
    hundreds: number; fifties: number; thirties: number; fours: number; sixes: number; fastestFifty: number; fastestHundred: number;
    wickets: number; economy: number; bestBowling: string; bestBowlingWickets: number; bestBowlingRuns: number; bowlingAverage: number;
    ballsBowled: number; runsConceded: number; threeWicketHauls: number; fiveWicketHauls: number; catches: number; runOuts: number;
    manOfTheMatchAwards: number;
}

export interface Player {
    id: string; name: string; nationality: string; role: PlayerRole; battingSkill: number; secondarySkill: number;
    style: BattingStyle; isOpener: boolean; isForeign: boolean; teamName?: string;
    customProfiles?: { [key in Format]?: { avg: number; sr: number } };
    stats: Record<Format, PlayerStats>;
}

export interface Team {
    id: string; name: string; shortName: string; primaryColor: string; secondaryColor: string; squad: Player[]; captains: { [key in Format]?: string };
}

export interface TeamData {
    id: string; name: string; shortName: string; homeGround: string; logo: string; primaryColor: string; secondaryColor: string; isDevelopmentTeam?: boolean;
}

export interface Ground {
    name: string; code: string; pitch: string; dimensions?: string; weather?: 'Sunny' | 'Overcast' | 'Rainy' | 'Humid' | 'Dry';
    boundarySize?: 'Small' | 'Medium' | 'Large'; outfieldSpeed?: 'Fast' | 'Medium' | 'Slow' | 'Lightning'; capacity?: number;
}

export interface Match {
    matchNumber: number | string; teamA: string; teamAId?: string; vs: string; teamB: string; teamBId?: string; date: string; group: 'Round-Robin' | 'Semi-Finals' | 'Final';
}

export interface Inning {
    teamId: string; teamName: string; score: number; wickets: number; overs: string; batting: BattingPerformance[]; bowling: BowlingPerformance[]; extras: number; recentBalls?: string[];
}

export interface BattingPerformance {
    playerId: string; playerName: string; runs: number; balls: number; fours: number; sixes: number; isOut: boolean; dismissalText: string; dismissal: { type: 'not out' | 'bowled' | 'caught'; bowlerId: string; fielderId?: string; }; ballsToFifty?: number; ballsToHundred?: number;
}

export interface BowlingPerformance {
    playerId: string; playerName: string; overs: string; maidens: number; runsConceded: number; wickets: number; ballsBowled: number;
}

export interface MatchResult {
    matchNumber: number | string; winnerId: string | null; loserId: string | null; isDraw?: boolean; summary: string; firstInning: Inning; secondInning: Inning; thirdInning?: Inning; fourthInning?: Inning; manOfTheMatch: { playerId: string; playerName: string; teamId: string; summary: string; }; tossWinnerId?: string; tossDecision?: 'bat' | 'bowl';
}

export interface Standing {
    teamId: string; teamName: string; played: number; won: number; lost: number; drawn: number; points: number; netRunRate: number; runsFor?: number; runsAgainst?: number;
}

export interface NewsArticle {
    id: string; headline: string; date: string; excerpt: string; content: string; type?: 'match' | 'transfer' | 'league' | 'squad';
}

export interface Award {
    season: number; format: Format; winnerTeamId: string; winnerTeamName: string;
    bestBatter: { playerId: string, playerName: string, teamName: string, runs: number };
    bestBowler: { playerId: string, playerName: string, teamName: string, wickets: number };
}

export interface ScoreLimits { maxRuns?: number; maxWickets?: number; }
export type InningLimits = { [key: number]: ScoreLimits; };

export interface BatterVsBowlerRecord { batterId: string; batterName: string; bowlerId: string; bowlerName: string; runs: number; balls: number; dismissals: number; }
export interface TeamVsTeamRecord { teamAId: string; teamBId: string; teamAName: string; teamBName: string; matches: number; teamAWins: number; }
export interface PlayerVsTeamRecord { playerId: string; playerName: string; playerRole: PlayerRole; vsTeamId: string; vsTeamName: string; runs: number; balls: number; dismissals: number; wickets: number; runsConceded: number; ballsBowled: number; }
export interface PromotionRecord { season: number; promotedTeamId: string; promotedTeamName: string; relegatedTeamId: string; relegatedTeamName: string; }

export interface Sponsorship { sponsorName: string; tournamentName: string; logoColor: string; tournamentLogo?: string; tvChannel?: string; tvLogo?: string; }
export interface Brand { name: string; color: string; style: string; logo: string; }
export interface TVChannel { id: string; name: string; logo: string; color: string; minPopularity: number; tier: 'Premium' | 'Standard' | 'Budget'; }

export interface GameData {
    userTeamId: string; teams: Team[]; grounds: Ground[]; allTeamsData: TeamData[]; allPlayers: Player[]; schedule: Record<Format, Match[]>; currentMatchIndex: Record<Format, number>; standings: Record<Format, Standing[]>; matchResults: Record<Format, MatchResult[]>; playingXIs: Record<string, Partial<Record<Format, string[]>>>; currentSeason: number; currentFormat: Format; awardsHistory: Award[]; records: { batterVsBowler: BatterVsBowlerRecord[]; teamVsTeam: TeamVsTeamRecord[]; playerVsTeam: PlayerVsTeamRecord[]; }; promotionHistory: PromotionRecord[]; popularity: number; sponsorships: Record<Format, Sponsorship>; news: NewsArticle[]; activeMatch: LiveMatchState | null; scoreLimits?: Record<string, Partial<Record<Format, InningLimits>>>; availableBrands?: Brand[]; availableTVChannels?: TVChannel[];
}

export interface LiveMatchState {
    status: 'toss' | 'ready' | 'inprogress' | 'inning_break' | 'completed'; match: Match; currentInningIndex: number; innings: Inning[]; target: number | null; currentBatters: { strikerId: string; nonStrikerId: string }; currentBowlerId: string; recentBalls: string[]; commentary: string[]; battingTeam: Team; bowlingTeam: Team; requiredRunRate: number; currentPartnership: { runs: number, balls: number }; fallOfWickets: { score: number, wicket: number, over: string, player: string }[]; waitingFor: 'openers' | 'batter' | 'bowler' | 'batter_arrival' | 'bowler_change' | null; strategies: { batting: Strategy; bowling: Strategy; }; autoPlayType: 'regular' | 'inning' | 'match' | null; tossWinnerId: string | null; tossDecision: 'bat' | 'bowl' | null;
}

export interface Message { id: string; text: string; sender: 'user' | 'model' | 'bot'; timestamp?: Date; }

export enum Format {
    T20 = 'Premier T20 League',
    ODI = 'Premier One-Day Cup',
    FIRST_CLASS = 'Premier First-Class Shield',
    DEVELOPMENT_T20 = 'Development T20 Cup',
    DEVELOPMENT_ODI = 'Development List-A Cup',
    DEVELOPMENT_FIRST_CLASS = 'Development First-Class Cup',
    RISE_T20 = 'Rise T20 Cup',
    RISE_ODI = 'Rise List-A Cup',
    RISE_FIRST_CLASS = 'Rise First-Class Cup'
}

export enum PlayerRole {
    BATSMAN = 'BT',
    WICKET_KEEPER = 'WK',
    ALL_ROUNDER = 'AR',
    SPIN_BOWLER = 'SB',
    FAST_BOWLER = 'BL',
}

export type BattingStyle = 'A' | 'D' | 'N' | 'NA';
export type Strategy = 'defensive' | 'balanced' | 'attacking';
export type AppState = 'MAIN_MENU' | 'TEAM_SELECTION' | 'CAREER_HUB';
export type CareerScreen = 'DASHBOARD' | 'LEAGUES' | 'LINEUPS' | 'EDITOR' | 'NEWS' | 'STATS' | 'SETTINGS' | 'PLAYER_PROFILE' | 'MATCH_RESULT' | 'FORWARD_RESULTS' | 'AWARDS_RECORDS' | 'TRANSFERS' | 'END_OF_FORMAT' | 'COMPARISON' | 'SCHEDULE' | 'LIVE_MATCH' | 'SPONSOR_ROOM' | 'CUSTOMIZATION';

export interface PlayerStats {
    matches: number; runs: number; highestScore: number; average: number; strikeRate: number; ballsFaced: number; dismissals: number;
    hundreds: number; fifties: number; thirties: number; fours: number; sixes: number; fastestFifty: number; fastestHundred: number;
    wickets: number; economy: number; bestBowling: string; bestBowlingWickets: number; bestBowlingRuns: number; bowlingAverage: number;
    ballsBowled: number; runsConceded: number; threeWicketHauls: number; fiveWicketHauls: number; catches: number; runOuts: number;
    manOfTheMatchAwards: number;
}

export interface Player {
    id: string; name: string; nationality: string; role: PlayerRole; battingSkill: number; secondarySkill: number;
    style: BattingStyle; isOpener: boolean; isForeign: boolean; teamName?: string;
    customProfiles?: { [key in Format]?: { avg: number; sr: number } };
    stats: Record<Format, PlayerStats>;
}

export interface Team {
    id: string; name: string; shortName: string; primaryColor: string; secondaryColor: string; squad: Player[]; captains: { [key in Format]?: string };
}

export interface TeamData {
    id: string; name: string; shortName: string; homeGround: string; logo: string; primaryColor: string; secondaryColor: string; isDevelopmentTeam?: boolean;
}

export interface Ground {
    name: string; code: string; pitch: string; dimensions?: string; weather?: 'Sunny' | 'Overcast' | 'Rainy' | 'Humid' | 'Dry';
    boundarySize?: 'Small' | 'Medium' | 'Large'; outfieldSpeed?: 'Fast' | 'Medium' | 'Slow' | 'Lightning'; capacity?: number;
}

export interface Match {
    matchNumber: number | string; teamA: string; teamAId?: string; vs: string; teamB: string; teamBId?: string; date: string; group: 'Round-Robin' | 'Semi-Finals' | 'Final';
}

export interface Inning {
    teamId: string; teamName: string; score: number; wickets: number; overs: string; batting: BattingPerformance[]; bowling: BowlingPerformance[]; extras: number; recentBalls?: string[];
}

export interface BattingPerformance {
    playerId: string; playerName: string; runs: number; balls: number; fours: number; sixes: number; isOut: boolean; dismissalText: string; dismissal: { type: 'not out' | 'bowled' | 'caught'; bowlerId: string; fielderId?: string; }; ballsToFifty?: number; ballsToHundred?: number;
}

export interface BowlingPerformance {
    playerId: string; playerName: string; overs: string; maidens: number; runsConceded: number; wickets: number; ballsBowled: number;
}

export interface MatchResult {
    matchNumber: number | string; winnerId: string | null; loserId: string | null; isDraw?: boolean; summary: string; firstInning: Inning; secondInning: Inning; thirdInning?: Inning; fourthInning?: Inning; manOfTheMatch: { playerId: string; playerName: string; teamId: string; summary: string; }; tossWinnerId?: string; tossDecision?: 'bat' | 'bowl';
}

export interface Standing {
    teamId: string; teamName: string; played: number; won: number; lost: number; drawn: number; points: number; netRunRate: number; runsFor?: number; runsAgainst?: number;
}

export interface NewsArticle {
    id: string; headline: string; date: string; excerpt: string; content: string; type?: 'match' | 'transfer' | 'league' | 'squad';
}

export interface Award {
    season: number; format: Format; winnerTeamId: string; winnerTeamName: string;
    bestBatter: { playerId: string, playerName: string, teamName: string, runs: number };
    bestBowler: { playerId: string, playerName: string, teamName: string, wickets: number };
}

export interface ScoreLimits { maxRuns?: number; maxWickets?: number; }
export type InningLimits = { [key: number]: ScoreLimits; };

export interface BatterVsBowlerRecord { batterId: string; batterName: string; bowlerId: string; bowlerName: string; runs: number; balls: number; dismissals: number; }
export interface TeamVsTeamRecord { teamAId: string; teamBId: string; teamAName: string; teamBName: string; matches: number; teamAWins: number; }
export interface PlayerVsTeamRecord { playerId: string; playerName: string; playerRole: PlayerRole; vsTeamId: string; vsTeamName: string; runs: number; balls: number; dismissals: number; wickets: number; runsConceded: number; ballsBowled: number; }
export interface PromotionRecord { season: number; promotedTeamId: string; promotedTeamName: string; relegatedTeamId: string; relegatedTeamName: string; }

export interface Sponsorship { sponsorName: string; tournamentName: string; logoColor: string; tournamentLogo?: string; tvChannel?: string; tvLogo?: string; }
export interface Brand { name: string; color: string; style: string; logo: string; }
export interface TVChannel { id: string; name: string; logo: string; color: string; minPopularity: number; tier: 'Premium' | 'Standard' | 'Budget'; }

export interface GameData {
    userTeamId: string; teams: Team[]; grounds: Ground[]; allTeamsData: TeamData[]; allPlayers: Player[]; schedule: Record<Format, Match[]>; currentMatchIndex: Record<Format, number>; standings: Record<Format, Standing[]>; matchResults: Record<Format, MatchResult[]>; playingXIs: Record<string, Partial<Record<Format, string[]>>>; currentSeason: number; currentFormat: Format; awardsHistory: Award[]; records: { batterVsBowler: BatterVsBowlerRecord[]; teamVsTeam: TeamVsTeamRecord[]; playerVsTeam: PlayerVsTeamRecord[]; }; promotionHistory: PromotionRecord[]; popularity: number; sponsorships: Record<Format, Sponsorship>; news: NewsArticle[]; activeMatch: LiveMatchState | null; scoreLimits?: Record<string, Partial<Record<Format, InningLimits>>>; availableBrands?: Brand[]; availableTVChannels?: TVChannel[];
}

export interface LiveMatchState {
    status: 'toss' | 'ready' | 'inprogress' | 'inning_break' | 'completed'; match: Match; currentInningIndex: number; innings: Inning[]; target: number | null; currentBatters: { strikerId: string; nonStrikerId: string }; currentBowlerId: string; recentBalls: string[]; commentary: string[]; battingTeam: Team; bowlingTeam: Team; requiredRunRate: number; currentPartnership: { runs: number, balls: number }; fallOfWickets: { score: number, wicket: number, over: string, player: string }[]; waitingFor: 'openers' | 'batter' | 'bowler' | 'batter_arrival' | 'bowler_change' | null; strategies: { batting: Strategy; bowling: Strategy; }; autoPlayType: 'regular' | 'inning' | 'match' | null; tossWinnerId: string | null; tossDecision: 'bat' | 'bowl' | null;
}

export interface Message { id: string; text: string; sender: 'user' | 'model' | 'bot'; timestamp?: Date; }

