import React, { useState, useEffect } from 'react';
import { AppState, GameData, Team, Format, MatchResult } from './types';
import { PLAYERS, TEAMS, GROUNDS, PRE_BUILT_SQUADS, INITIAL_SPONSORSHIPS, INITIAL_NEWS } from './data';
import { LoadingSpinner, generateLeagueSchedule } from './utils';

// Components
import { MainMenu, TeamSelection } from './components/GameComponents';
import CareerHub from './components/CareerHub';

export const App = () => {
  const [appState, setAppState] = useState<AppState>('MAIN_MENU');
  const [gameData, setGameData] = useState<GameData | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState<'light' | 'dark'>('dark');
  const [feedbackMessage, setFeedbackMessage] = useState<{ text: string; type: 'success' | 'error' } | null>(null);
  const [hasSaveData, setHasSaveData] = useState(false);

  useEffect(() => {
    const savedTheme = localStorage.getItem('cricketManagerTheme') || 'dark';
    setTheme(savedTheme as 'light' | 'dark');
    const savedGame = localStorage.getItem('cricketManagerSave');
    if (savedGame) {
        setHasSaveData(true);
    }
    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (theme === 'light') document.documentElement.classList.remove('dark');
    else document.documentElement.classList.add('dark');
    localStorage.setItem('cricketManagerTheme', theme);
  }, [theme]);

  useEffect(() => {
    if (gameData && !isLoading) {
      localStorage.setItem('cricketManagerSave', JSON.stringify(gameData));
      setHasSaveData(true);
    }
  }, [gameData, isLoading]);

  const showFeedback = (text: string, type: 'success' | 'error' = 'success') => {
    setFeedbackMessage({ text, type });
    setTimeout(() => setFeedbackMessage(null), 2500);
  };

  const saveGame = () => { showFeedback("Progress is saved automatically!"); };

  const loadGame = () => {
    if (window.confirm("Loading a saved game will overwrite your current unsaved progress. Continue?")) {
        const savedGame = localStorage.getItem('cricketManagerSave');
        if (savedGame) {
            try {
                setGameData(JSON.parse(savedGame));
                showFeedback("Game Loaded!", "success");
                setAppState('CAREER_HUB');
            } catch (e) {
                localStorage.removeItem('cricketManagerSave');
                setHasSaveData(false);
                showFeedback("Failed to load saved game.", "error");
            }
        }
    }
  };

  const resumeGame = () => {
    const savedGame = localStorage.getItem('cricketManagerSave');
    if (savedGame) {
        try {
            setGameData(JSON.parse(savedGame));
            setAppState('CAREER_HUB');
            showFeedback("Game Resumed!", "success");
        } catch(e) {
            localStorage.removeItem('cricketManagerSave');
            setHasSaveData(false);
            showFeedback("Failed to load saved game.", "error");
        }
    }
  };

  const initializeNewGame = (userTeamId: string) => {
    setIsLoading(true);
    const allPlayers = PLAYERS.map(p => JSON.parse(JSON.stringify(p)));
    const allPlayersById = new Map(allPlayers.map(p => [p.id, p]));

    const initialTeams: Team[] = TEAMS.map(teamData => {
        const squadIds = PRE_BUILT_SQUADS[teamData.id] || [];
        const squad = squadIds.map(id => allPlayersById.get(id)).filter(Boolean) as any;
        return {
            id: teamData.id,
            name: teamData.name,
            shortName: teamData.shortName,
            primaryColor: teamData.primaryColor,
            secondaryColor: teamData.secondaryColor,
            squad: squad,
            captains: {}
        };
    });

    const initialStandings = (teams: Team[]) => teams.map(team => ({ 
        teamId: team.id, teamName: team.name, played: 0, won: 0, lost: 0, drawn: 0, points: 0, netRunRate: 0, runsFor: 0, runsAgainst: 0 
    }));

    const mainTeams = initialTeams.filter(t => !TEAMS.find(td => td.id === t.id)?.isDevelopmentTeam);
    const devTeams = initialTeams.filter(t => TEAMS.find(td => td.id === t.id)?.isDevelopmentTeam);

    const schedules = {
        [Format.T20]: generateLeagueSchedule(mainTeams, Format.T20),
        [Format.ODI]: generateLeagueSchedule(mainTeams, Format.ODI),
        [Format.FIRST_CLASS]: generateLeagueSchedule(mainTeams, Format.FIRST_CLASS),
        [Format.DEVELOPMENT_T20]: generateLeagueSchedule(devTeams, Format.DEVELOPMENT_T20),
        [Format.DEVELOPMENT_ODI]: generateLeagueSchedule(devTeams, Format.DEVELOPMENT_ODI),
        [Format.DEVELOPMENT_FIRST_CLASS]: generateLeagueSchedule(devTeams, Format.DEVELOPMENT_FIRST_CLASS),
        [Format.RISE_T20]: generateLeagueSchedule(devTeams, Format.RISE_T20),
        [Format.RISE_ODI]: generateLeagueSchedule(devTeams, Format.RISE_ODI),
        [Format.RISE_FIRST_CLASS]: generateLeagueSchedule(devTeams, Format.RISE_FIRST_CLASS),
    };

    const newGameData: GameData = {
      userTeamId,
      teams: initialTeams,
      grounds: [...GROUNDS],
      allTeamsData: [...TEAMS],
      allPlayers,
      schedule: schedules,
      currentMatchIndex: { [Format.T20]: 0, [Format.ODI]: 0, [Format.FIRST_CLASS]: 0, [Format.DEVELOPMENT_T20]: 0, [Format.DEVELOPMENT_ODI]: 0, [Format.DEVELOPMENT_FIRST_CLASS]: 0, [Format.RISE_T20]: 0, [Format.RISE_ODI]: 0, [Format.RISE_FIRST_CLASS]: 0 },
      standings: { [Format.T20]: initialStandings(mainTeams), [Format.ODI]: initialStandings(mainTeams), [Format.FIRST_CLASS]: initialStandings(mainTeams), [Format.DEVELOPMENT_T20]: initialStandings(devTeams), [Format.DEVELOPMENT_ODI]: initialStandings(devTeams), [Format.DEVELOPMENT_FIRST_CLASS]: initialStandings(devTeams), [Format.RISE_T20]: initialStandings(devTeams), [Format.RISE_ODI]: initialStandings(devTeams), [Format.RISE_FIRST_CLASS]: initialStandings(devTeams) },
      matchResults: Object.values(Format).reduce((acc, f) => { acc[f] = []; return acc; }, {} as any),
      playingXIs: {},
      currentSeason: 1,
      currentFormat: Format.T20, 
      awardsHistory: [],
      records: { batterVsBowler: [], teamVsTeam: [], playerVsTeam: [] },
      promotionHistory: [],
      popularity: 50,
      sponsorships: INITIAL_SPONSORSHIPS,
      news: INITIAL_NEWS,
      activeMatch: null,
      availableBrands: [],
      availableTVChannels: []
    };

    setGameData(newGameData);
    setAppState('CAREER_HUB');
    setIsLoading(false);
  };

  const renderContent = () => {
    if (isLoading) return <div className="h-full flex items-center justify-center bg-gray-900"><LoadingSpinner /></div>;
    switch(appState) {
        case 'MAIN_MENU': return <MainMenu onStartNewGame={() => setAppState('TEAM_SELECTION')} onResumeGame={resumeGame} hasSaveData={hasSaveData} />;
        case 'TEAM_SELECTION': return <TeamSelection onTeamSelected={initializeNewGame} theme={theme} />;
        case 'CAREER_HUB':
            if (gameData) return <CareerHub gameData={gameData} setGameData={setGameData} onResetGame={() => { localStorage.removeItem('cricketManagerSave'); setAppState('MAIN_MENU'); setGameData(null); }} theme={theme} setTheme={setTheme} saveGame={saveGame} loadGame={loadGame} showFeedback={showFeedback} />;
            setAppState('MAIN_MENU'); return null;
        default: return null;
    }
  }

  return (
    <div className="bg-gray-100 dark:bg-gray-950 min-h-screen flex items-center justify-center font-sans">
      <div className="w-full max-w-md h-screen max-h-[932px] bg-white dark:bg-[#111111] border-4 border-gray-300 dark:border-gray-800 rounded-[40px] shadow-2xl overflow-hidden relative flex flex-col">
        {renderContent()}
        {feedbackMessage && (
            <div className={`absolute bottom-28 left-1/2 -translate-x-1/2 px-6 py-3 rounded-2xl z-50 shadow-2xl text-white font-black italic tracking-tighter ${feedbackMessage.type === 'success' ? 'bg-teal-500' : 'bg-red-500'}`}>{feedbackMessage.text}</div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { Match, GameData, MatchResult, Team, Player, Inning } from '../types';
import { getPlayerById, formatOvers } from '../utils';

interface Gameplay2DScreenProps {
    match: Match;
    gameData: GameData;
    onMatchComplete: (result: MatchResult) => void;
    onExit: () => void;
}

const FIELD_WIDTH = 600;
const FIELD_HEIGHT = 650;
const CENTER_X = FIELD_WIDTH / 2;
const CENTER_Y = FIELD_HEIGHT / 2;
const PITCH_START_Y = 220;
const PITCH_END_Y = 460;
const BOUNDARY_RADIUS = 285;
const BALL_RADIUS = 3.5;
const FIELDER_RADIUS = 8;

type BallState = 'dead' | 'runup' | 'bowling' | 'hit' | 'fielding' | 'boundary' | 'wicket';
type Aggression = 'Defensive' | 'Balanced' | 'Attacking';

interface Fielder {
    id: string; x: number; y: number; role: 'keeper' | 'bowler' | 'fielder'; speed: number; name: string;
}

export const Gameplay2DScreen: React.FC<Gameplay2DScreenProps> = ({ match, gameData, onMatchComplete, onExit }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);
    const [allPlayers, setAllPlayers] = useState<Player[]>([]);
    const [inningsState, setInningsState] = useState<Inning[]>([]);
    const [currentInningIndex, setCurrentInningIndex] = useState(0);
    const [battingTeam, setBattingTeam] = useState<Team | null>(null);
    const [bowlingTeam, setBowlingTeam] = useState<Team | null>(null);
    const [target, setTarget] = useState<number | null>(null);
    const [strikerId, setStrikerId] = useState<string>('');
    const [nonStrikerId, setNonStrikerId] = useState<string>('');
    const [bowlerId, setBowlerId] = useState<string>('');
    const [aggression, setAggression] = useState<Aggression>('Balanced');
    const [modalType, setModalType] = useState<'batter' | 'bowler' | 'openers' | null>(null);
    const [gameOver, setGameOver] = useState(false);
    const [ballPhase, setBallPhase] = useState<BallState>('dead');
    const [selectedModalId, setSelectedModalId] = useState('');
    const [selectedModalId2, setSelectedModalId2] = useState('');

    const game = useRef({
        ball: { x: CENTER_X, y: PITCH_START_Y, z: 0, vx: 0, vy: 0, vz: 0, state: 'dead' as BallState, bounces: 0 },
        bowlerPos: { x: CENTER_X, y: PITCH_START_Y - 30 },
        fielders: [] as Fielder[],
        draggedFielder: null as number | null,
        strikerId: '', nonStrikerId: '', bowlerId: '', aggression: 'Balanced' as Aggression,
        currentInningIndex: 0, target: null as number | null, gameOver: false, matchCompleteTriggered: false
    });

    useEffect(() => { 
        game.current.strikerId = strikerId; 
        game.current.nonStrikerId = nonStrikerId;
        game.current.bowlerId = bowlerId;
        game.current.aggression = aggression;
        game.current.currentInningIndex = currentInningIndex;
        game.current.target = target;
        game.current.gameOver = gameOver;
    }, [strikerId, nonStrikerId, bowlerId, aggression, currentInningIndex, target, gameOver]);

    useEffect(() => {
        const tA = gameData.teams.find(t => t.name === match.teamA) || gameData.teams[0];
        const tB = gameData.teams.find(t => t.name === match.teamB) || gameData.teams[1];
        const getXI = (t: Team) => {
            const xiIds = gameData.playingXIs[t.id]?.[gameData.currentFormat];
            if (xiIds && xiIds.length === 11) return xiIds.map(id => t.squad.find(p => p.id === id)).filter(Boolean) as Player[];
            return t.squad.slice(0, 11); 
        };
        const pA = getXI(tA); const pB = getXI(tB);
        setAllPlayers([...pA, ...pB]);
        const createInning = (team: Team, opp: Team, pList: Player[]): Inning => ({
            teamId: team.id, teamName: team.name, score: 0, wickets: 0, overs: '0.0', extras: 0,
            batting: pList.map(p => ({ playerId: p.id, playerName: p.name, runs: 0, balls: 0, fours: 0, sixes: 0, isOut: false, dismissalText: 'not out', dismissal: { type: 'not out', bowlerId: '' } })),
            bowling: getXI(opp).map(p => ({ playerId: p.id, playerName: p.name, overs: '0.0', maidens: 0, runsConceded: 0, wickets: 0, ballsBowled: 0 })),
            recentBalls: []
        });
        setInningsState([ createInning(tA, tB, pA), createInning(tB, tA, pB) ]);
        setBattingTeam(tA); setBowlingTeam(tB); setModalType('openers');
    }, []);

    const updateScore = useCallback((runs: number, wkt: number, balls: number = 1) => {
        setInningsState(prev => {
            const newInnings = [...prev];
            const inn = newInnings[game.current.currentInningIndex];
            inn.score += runs; inn.wickets += wkt;
            const b = inn.batting.find(p => p.playerId === game.current.strikerId);
            const bowl = inn.bowling.find(p => p.playerId === game.current.bowlerId);
            if (b) {
                b.runs += runs; b.balls += balls; 
                if (runs === 4) b.fours++; if (runs === 6) b.sixes++;
                if (wkt) { b.isOut = true; b.dismissalText = "b " + (bowl?.playerName || 'Bowler'); }
            }
            if (bowl) {
                bowl.runsConceded += runs; bowl.ballsBowled += balls; bowl.wickets += wkt;
                bowl.overs = formatOvers(bowl.ballsBowled);
            }
            inn.overs = formatOvers(inn.bowling.reduce((acc, x) => acc + x.ballsBowled, 0));
            inn.recentBalls = [(wkt ? 'W' : runs.toString()), ...(inn.recentBalls || [])].slice(0, 6);
            return newInnings;
        });
        if (runs % 2 !== 0) {
            const oldS = game.current.strikerId;
            setStrikerId(game.current.nonStrikerId);
            setNonStrikerId(oldS);
        }
    }, []);

    const processBall = () => {
        const p = game.current;
        if (p.ball.state === 'dead' || p.gameOver) return;
        if (p.ball.state === 'runup') {
            p.bowlerPos.y += 4.5;
            if (p.bowlerPos.y >= PITCH_START_Y) {
                p.ball.state = 'bowling'; p.ball.x = p.bowlerPos.x; p.ball.y = p.bowlerPos.y; p.ball.vx = (Math.random() - 0.5) * 2; p.ball.vy = 10;
            }
        } else if (p.ball.state === 'bowling') {
            p.ball.x += p.ball.vx; p.ball.y += p.ball.vy;
            if (p.ball.y >= PITCH_END_Y - 8) {
                const bat = getPlayerById(p.strikerId, allPlayers);
                const bowl = getPlayerById(p.bowlerId, allPlayers);
                let diff = bat.battingSkill - bowl.secondarySkill + (Math.random() * 60 - 30);
                if (p.aggression === 'Attacking') diff += 15;
                if (diff < -40 && Math.random() < 0.2) {
                    updateScore(0, 1); p.ball.state = 'dead'; setBallPhase('dead');
                    if (inningsState[p.currentInningIndex].wickets < 9) {
                        if (battingTeam?.id === gameData.userTeamId) setTimeout(() => setModalType('batter'), 1000);
                        else {
                            const next = inningsState[p.currentInningIndex].batting.find(x => !x.isOut && x.playerId !== p.strikerId && x.playerId !== p.nonStrikerId);
                            if (next) setStrikerId(next.playerId);
                        }
                    }
                } else {
                    p.ball.state = 'hit';
                    const angle = Math.random() * Math.PI * 2;
                    const power = 4 + Math.random() * 6;
                    p.ball.vx = Math.cos(angle) * power; p.ball.vy = Math.sin(angle) * power; p.ball.vz = (p.aggression === 'Attacking' ? 10 : 2);
                }
            }
        } else if (p.ball.state === 'hit') {
            p.ball.x += p.ball.vx; p.ball.y += p.ball.vy;
            p.ball.vx *= 0.985; p.ball.vy *= 0.985;
            if (p.ball.z > 0 || p.ball.vz > 0) { p.ball.z += p.ball.vz; p.ball.vz -= 0.4; if (p.ball.z < 0) { p.ball.z = 0; p.ball.vz *= -0.4; p.ball.bounces++; } }
            const dist = Math.sqrt(Math.pow(p.ball.x - CENTER_X, 2) + Math.pow(p.ball.y - CENTER_Y, 2));
            if (dist >= BOUNDARY_RADIUS) {
                updateScore(p.ball.bounces === 0 ? 6 : 4, 0); p.ball.state = 'dead'; setBallPhase('dead');
            } else {
                let intercepted = false;
                p.fielders.forEach(f => {
                    const fd = Math.sqrt(Math.pow(f.x - p.ball.x, 2) + Math.pow(f.y - p.ball.y, 2));
                    const angle = Math.atan2(p.ball.y - f.y, p.ball.x - f.x);
                    f.x += Math.cos(angle) * 3; f.y += Math.sin(angle) * 3;
                    if (fd < 15 && !intercepted) {
                        if (p.ball.z > 5 && p.ball.bounces === 0) { updateScore(0, 1); p.ball.state = 'dead'; setBallPhase('dead'); intercepted = true; handleDismissal(); }
                        else if (p.ball.z < 10) { const runs = dist > 200 ? 3 : dist > 100 ? 2 : dist > 40 ? 1 : 0; updateScore(runs, 0); p.ball.state = 'dead'; setBallPhase('dead'); intercepted = true; }
                    }
                });
                if (!intercepted && Math.abs(p.ball.vx) < 0.2) { updateScore(dist > 100 ? 1 : 0, 0); p.ball.state = 'dead'; setBallPhase('dead'); }
            }
        }
    };

    const handleDismissal = () => {
        const inn = inningsState[game.current.currentInningIndex];
        if (inn.wickets + 1 >= 10) return;
        if (battingTeam?.id === gameData.userTeamId) setTimeout(() => setModalType('batter'), 1000);
        else {
            const next = inn.batting.find(x => !x.isOut && x.playerId !== game.current.strikerId && x.playerId !== game.current.nonStrikerId);
            if (next) setStrikerId(next.playerId);
        }
    };

    useEffect(() => {
        const ctx = canvasRef.current?.getContext('2d');
        const loop = () => { processBall(); if (ctx) {
            ctx.fillStyle = "#1b3316"; ctx.fillRect(0, 0, FIELD_WIDTH, FIELD_HEIGHT);
            ctx.strokeStyle = "rgba(255,255,255,0.1)"; ctx.beginPath(); ctx.arc(CENTER_X, CENTER_Y, 150, 0, Math.PI*2); ctx.stroke();
            ctx.strokeStyle = "rgba(255,255,255,0.5)"; ctx.lineWidth = 2; ctx.beginPath(); ctx.arc(CENTER_X, CENTER_Y, BOUNDARY_RADIUS, 0, Math.PI*2); ctx.stroke();
            ctx.fillStyle = "#ccb68d"; ctx.fillRect(CENTER_X - 15, PITCH_START_Y, 30, PITCH_END_Y - PITCH_START_Y);
            game.current.fielders.forEach(f => { ctx.fillStyle = "#FDE047"; ctx.beginPath(); ctx.arc(f.x, f.y, FIELDER_RADIUS, 0, Math.PI*2); ctx.fill(); });
            const b = game.current.ball;
            if (b.state !== 'dead') { ctx.fillStyle = "rgba(0,0,0,0.4)"; ctx.beginPath(); ctx.arc(b.x, b.y, BALL_RADIUS + (b.z/4), 0, Math.PI*2); ctx.fill(); ctx.fillStyle = "white"; ctx.beginPath(); ctx.arc(b.x, b.y-b.z, BALL_RADIUS, 0, Math.PI*2); ctx.fill(); }
            ctx.fillStyle = "#EF4444"; ctx.beginPath(); ctx.arc(game.current.bowlerPos.x, game.current.bowlerPos.y, FIELDER_RADIUS, 0, Math.PI*2); ctx.fill();
            ctx.fillStyle = "#3B82F6"; ctx.beginPath(); ctx.arc(CENTER_X, PITCH_END_Y + 5, FIELDER_RADIUS, 0, Math.PI*2); ctx.fill();
        } requestAnimationFrame(loop); }; loop();
    }, []);

    const confirmOpeners = () => {
        if (selectedModalId && selectedModalId2) {
            setStrikerId(selectedModalId); setNonStrikerId(selectedModalId2); setModalType(null);
            const fds: Fielder[] = [{id:'wk', x:CENTER_X, y:PITCH_END_Y+40, role:'keeper', speed:0.8, name:'WK'}, {id:'bwl', x:CENTER_X, y:PITCH_START_Y-20, role:'bowler', speed:1.0, name:'BWL'}];
            for(let i=0; i<9; i++) fds.push({id:`f${i}`, x:CENTER_X+Math.cos(i*40)*180, y:CENTER_Y+Math.sin(i*40)*180, role:'fielder', speed:1, name:`F${i+1}`});
            game.current.fielders = fds; setBowlerId(inningsState[currentInningIndex].bowling[0].playerId);
        }
    };

    const currentInning = inningsState[currentInningIndex];
    const striker = currentInning?.batting.find(b => b.playerId === strikerId);
    const nonStriker = currentInning?.batting.find(b => b.playerId === nonStrikerId);
    const bowler = currentInning?.bowling.find(b => b.playerId === bowlerId);

    return (
        <div className="flex flex-col h-full bg-black text-white overflow-hidden relative font-sans italic tracking-tighter">
            <style>{` .slanted { clip-path: polygon(0% 0%, 100% 0%, 90% 100%, 0% 100%); } .score-dot { width: 18px; height: 18px; border-radius: 50%; border: 1px solid rgba(255,255,255,0.4); display: flex; align-items: center; justify-content: center; font-size: 9px; font-weight: 900; } `}</style>
            <div className="flex-1 relative bg-[#1c2e17] flex justify-center">
                <canvas ref={canvasRef} width={FIELD_WIDTH} height={FIELD_HEIGHT} className="h-full w-auto object-contain" />
                <div className="absolute bottom-8 left-0 w-full px-4 flex justify-start pointer-events-none z-40">
                    <div className="flex items-end drop-shadow-xl">
                        <div className="flex flex-col">
                            <div className="bg-pink-600 slanted h-12 flex items-center px-4 pr-10 min-w-[130px]">
                                <span className="text-3xl font-black text-white italic leading-none">{currentInning?.score}-{currentInning?.wickets}</span>
                            </div>
                            <div className="bg-black/90 slanted h-6 flex items-center px-3 pr-8 border-l-4 border-pink-500 mt-[-4px]">
                                <span className="text-[9px] font-black text-zinc-400 mr-2">OVERS</span>
                                <span className="text-xs font-black text-white">{currentInning?.overs}</span>
                            </div>
                        </div>
                        <div className="flex bg-zinc-900 h-12 ml-[-12px] border-b-4 border-pink-600">
                            <div className="flex flex-col justify-center px-6 min-w-[120px] border-r border-white/10">
                                <span className="text-[10px] font-black text-white uppercase">{striker?.playerName.split(' ').pop()}</span>
                                <span className="text-xl font-black text-pink-500 leading-none">{striker?.runs} <small className="text-[10px] text-zinc-400">({striker?.balls})</small></span>
                            </div>
                            <div className="flex flex-col justify-center px-6 min-w-[120px] opacity-60">
                                <span className="text-[10px] font-black text-white uppercase">{nonStriker?.playerName.split(' ').pop()}</span>
                                <span className="text-xl font-black text-white leading-none">{nonStriker?.runs} <small className="text-[10px] text-zinc-400">({nonStriker?.balls})</small></span>
                            </div>
                            <div className="flex flex-col justify-center px-6 min-w-[120px] bg-pink-900/10">
                                <span className="text-[9px] font-black text-pink-400 uppercase">BOWLING</span>
                                <span className="text-xl font-black text-white leading-none">{bowler?.wickets}-{bowler?.runsConceded}</span>
                            </div>
                        </div>
                        <div className="flex bg-black/95 h-10 items-center px-6 ml-[-4px] self-end mb-[-4px]">
                            <div className="flex gap-1">
                                {currentInning?.recentBalls?.map((b, i) => <div key={i} className="score-dot">{b}</div>)}
                            </div>
                        </div>
                    </div>
                </div>
            </div>
            <div className="bg-zinc-950 p-4 border-t border-white/5">
                <div className="flex gap-2 h-16">
                    {ballPhase === 'dead' && !gameOver && !modalType && (
                        <button onClick={() => { setBallPhase('runup'); game.current.ball.state = 'runup'; }} className="flex-[3] bg-pink-600 rounded-2xl font-black text-2xl italic shadow-2xl animate-pulse">PLAY BALL</button>
                    )}
                    <button onClick={onExit} className="flex-1 bg-zinc-800 rounded-2xl font-black text-xs text-zinc-400 uppercase">Quit</button>
                </div>
            </div>
            {modalType && (
                <div className="absolute inset-0 bg-black/95 z-[100] flex items-center justify-center p-8">
                    <div className="w-full max-w-sm bg-zinc-900 p-8 rounded-[40px] border-2 border-pink-500/20">
                        <h3 className="text-2xl font-black text-center mb-8 uppercase italic leading-none">{modalType} Selection</h3>
                        <select className="w-full p-4 bg-zinc-800 rounded-2xl text-white font-bold mb-4" value={selectedModalId} onChange={e => setSelectedModalId(e.target.value)}>
                            <option value="">Choose Player</option>
                            {(modalType === 'bowler' ? currentInning.bowling : currentInning.batting).map(p => <option key={p.playerId} value={p.playerId}>{p.playerName}</option>)}
                        </select>
                        {modalType === 'openers' && (
                            <select className="w-full p-4 bg-zinc-800 rounded-2xl text-white font-bold mb-4" value={selectedModalId2} onChange={e => setSelectedModalId2(e.target.value)}>
                                <option value="">Non-Striker</option>
                                {currentInning.batting.filter(p => p.playerId !== selectedModalId).map(p => <option key={p.playerId} value={p.playerId}>{p.playerName}</option>)}
                            </select>
                        )}
                        <button disabled={!selectedModalId} onClick={() => { if(modalType==='openers')confirmOpeners(); else if(modalType==='batter')setStrikerId(selectedModalId); else setBowlerId(selectedModalId); setModalType(null); }} className="w-full bg-pink-600 py-5 rounded-2xl font-black text-white uppercase italic text-lg transition-all">Confirm</button>
                    </div>
                </div>
            )}
        </div>
    );
};

