export const generateLeagueSchedule = (teams: Team[], format: Format): Match[] => {
    const matches: Match[] = [];
    if (teams.length < 2) return [];
    for(let i=0; i<teams.length; i++) {
        for(let j=i+1; j<teams.length; j++) {
            matches.push({ matchNumber: matches.length + 1, teamA: teams[i].name, vs: 'vs', teamB: teams[j].name, date: `Match Day ${matches.length + 1}`, group: 'Round-Robin' });
        }
    }
    return matches;
};

