import React, { useState, useEffect } from 'react';
import { AppState, GameData, Team, Format, MatchResult, Standing } from './types';
import { PLAYERS, TEAMS, GROUNDS, PRE_BUILT_SQUADS, INITIAL_SPONSORSHIPS, INITIAL_NEWS } from './data';
import { LoadingSpinner, generateLeagueSchedule } from './utils';

// Components
import { MainMenu, TeamSelection } from './components/GameComponents';
import CareerHub from './components/CareerHub';

export const App = () => {
  const [appState, setAppState] = useState<AppState>('MAIN_MENU');
  const [gameData, setGameData] = useState<GameData | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [theme, setTheme] = useState<'light' | 'dark'>('dark');
  const [feedbackMessage, setFeedbackMessage] = useState<{ text: string; type: 'success' | 'error' } | null>(null);
  const [hasSaveData, setHasSaveData] = useState(false);

  useEffect(() => {
    const savedTheme = localStorage.getItem('cricketManagerTheme') || 'dark';
    setTheme(savedTheme as 'light' | 'dark');
    const savedGame = localStorage.getItem('cricketManagerSave');
    if (savedGame) {
        setHasSaveData(true);
    }
    setIsLoading(false);
  }, []);

  useEffect(() => {
    if (theme === 'light') document.documentElement.classList.remove('dark');
    else document.documentElement.classList.add('dark');
    localStorage.setItem('cricketManagerTheme', theme);
  }, [theme]);

  useEffect(() => {
    if (gameData && !isLoading) {
      localStorage.setItem('cricketManagerSave', JSON.stringify(gameData));
      setHasSaveData(true);
    }
  }, [gameData, isLoading]);

  const showFeedback = (text: string, type: 'success' | 'error' = 'success') => {
    setFeedbackMessage({ text, type });
    setTimeout(() => setFeedbackMessage(null), 2500);
  };

  const resumeGame = () => {
    const savedGame = localStorage.getItem('cricketManagerSave');
    if (savedGame) {
        try {
            setGameData(JSON.parse(savedGame));
            setAppState('CAREER_HUB');
            showFeedback("Game Resumed!", "success");
        } catch(e) {
            localStorage.removeItem('cricketManagerSave');
            setHasSaveData(false);
            showFeedback("Failed to load saved game.", "error");
        }
    }
  };

  const initializeNewGame = (userTeamId: string) => {
    setIsLoading(true);
    const allPlayersRegistry = PLAYERS.map(p => JSON.parse(JSON.stringify(p)));
    const allPlayersById = new Map(allPlayersRegistry.map(p => [p.id, p]));

    const initialTeams: Team[] = TEAMS.map(teamData => {
        const squadIds = PRE_BUILT_SQUADS[teamData.id] || [];
        const squad = squadIds.map(id => {
            const p = allPlayersById.get(id);
            return p ? JSON.parse(JSON.stringify(p)) : null;
        }).filter(Boolean);

        return {
            id: teamData.id,
            name: teamData.name,
            shortName: teamData.shortName,
            primaryColor: teamData.primaryColor,
            secondaryColor: teamData.secondaryColor,
            squad: squad,
            captains: {}
        };
    });

    const initialStandings = (teams: Team[]): Standing[] => teams.map(team => ({ 
        teamId: team.id, teamName: team.name, played: 0, won: 0, lost: 0, drawn: 0, points: 0, netRunRate: 0, runsFor: 0, runsAgainst: 0 
    }));

    const mainTeams = initialTeams.filter(t => !TEAMS.find(td => td.id === t.id)?.isDevelopmentTeam);
    const devTeams = initialTeams.filter(t => TEAMS.find(td => td.id === t.id)?.isDevelopmentTeam);

    const schedules = {
        [Format.T20]: generateLeagueSchedule(mainTeams, Format.T20),
        [Format.ODI]: generateLeagueSchedule(mainTeams, Format.ODI),
        [Format.FIRST_CLASS]: generateLeagueSchedule(mainTeams, Format.FIRST_CLASS),
        [Format.DEVELOPMENT_T20]: generateLeagueSchedule(devTeams, Format.DEVELOPMENT_T20),
        [Format.DEVELOPMENT_ODI]: generateLeagueSchedule(devTeams, Format.DEVELOPMENT_ODI),
        [Format.DEVELOPMENT_FIRST_CLASS]: generateLeagueSchedule(devTeams, Format.DEVELOPMENT_FIRST_CLASS),
        [Format.RISE_T20]: generateLeagueSchedule(devTeams, Format.RISE_T20),
        [Format.RISE_ODI]: generateLeagueSchedule(devTeams, Format.RISE_ODI),
        [Format.RISE_FIRST_CLASS]: generateLeagueSchedule(devTeams, Format.RISE_FIRST_CLASS),
    };

    const newGameData: GameData = {
      userTeamId,
      teams: initialTeams,
      grounds: [...GROUNDS],
      allTeamsData: [...TEAMS],
      allPlayers: allPlayersRegistry,
      schedule: schedules,
      currentMatchIndex: Object.values(Format).reduce((acc, f) => ({ ...acc, [f]: 0 }), {} as any),
      standings: { 
          [Format.T20]: initialStandings(mainTeams), [Format.ODI]: initialStandings(mainTeams), [Format.FIRST_CLASS]: initialStandings(mainTeams),
          [Format.DEVELOPMENT_T20]: initialStandings(devTeams), [Format.DEVELOPMENT_ODI]: initialStandings(devTeams), [Format.DEVELOPMENT_FIRST_CLASS]: initialStandings(devTeams),
          [Format.RISE_T20]: initialStandings(devTeams), [Format.RISE_ODI]: initialStandings(devTeams), [Format.RISE_FIRST_CLASS]: initialStandings(devTeams)
      },
      matchResults: Object.values(Format).reduce((acc, f) => ({ ...acc, [f]: [] }), {} as any),
      playingXIs: {},
      currentSeason: 1,
      currentFormat: Format.T20, 
      awardsHistory: [],
      records: { batterVsBowler: [], teamVsTeam: [], playerVsTeam: [] },
      promotionHistory: [],
      popularity: 50,
      sponsorships: INITIAL_SPONSORSHIPS,
      news: INITIAL_NEWS,
      activeMatch: null,
      availableBrands: [],
      availableTVChannels: []
    };

    setGameData(newGameData);
    setAppState('CAREER_HUB');
    setIsLoading(false);
  };

  const renderContent = () => {
    if (isLoading) return <div className="h-full flex items-center justify-center bg-gray-900"><LoadingSpinner /></div>;
    switch(appState) {
        case 'MAIN_MENU': return <MainMenu onStartNewGame={() => setAppState('TEAM_SELECTION')} onResumeGame={resumeGame} hasSaveData={hasSaveData} />;
        case 'TEAM_SELECTION': return <TeamSelection onTeamSelected={initializeNewGame} theme={theme} />;
        case 'CAREER_HUB':
            if (gameData) return <CareerHub gameData={gameData} setGameData={setGameData} onResetGame={() => { localStorage.removeItem('cricketManagerSave'); setAppState('MAIN_MENU'); setGameData(null); }} theme={theme} setTheme={setTheme} saveGame={() => showFeedback("Game Saved!")} loadGame={() => {}} showFeedback={showFeedback} />;
            setAppState('MAIN_MENU'); return null;
        default: return null;
    }
  }

  return (
    <div className="bg-gray-100 dark:bg-gray-950 min-h-screen flex items-center justify-center font-sans">
      <div className="w-full max-w-md h-screen max-h-[932px] bg-white dark:bg-[#111111] border-4 border-gray-300 dark:border-gray-800 rounded-[40px] shadow-2xl overflow-hidden relative flex flex-col">
        {renderContent()}
        {feedbackMessage && (
            <div className={`absolute bottom-28 left-1/2 -translate-x-1/2 px-6 py-3 rounded-2xl z-50 shadow-2xl text-white font-black italic tracking-tighter ${feedbackMessage.type === 'success' ? 'bg-teal-500' : 'bg-red-500'}`}>{feedbackMessage.text}</div>
        )}
      </div>
    </div>
  );
};

